INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Warlock', 'Warlock [Character]', 'Warlock', 'basic', '["robe"]', '["firebrac","icebrac","lightbrac","elebrac"]', -195, -65, 'portrait', 30, 30, 40, 50, 85, 75, 1, 'Warlock - They strike with combination of strong offensive and elemental magic. Their wide-range of strong attacks lead in battlefield and save other family members. They can use instantly changing elemental magic according to Monster&amp;apos;s attribute.', 'Crecemento Robe', 'Crecemento Fire Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Fighter', 'Fighter [Character]', 'Fighter', 'basic', '["leather","metal"]', '["sword","shield","rap","sabre","gs","pole","dag","pistol","blunt","jav"]', -65, 0, 'portrait', 70, 60, 70, 60, 40, 50, 1, 'Fighter - They fight on the front line and are capable of using a wide variety of weapons. They are key characters of any MCC or Squad.', 'Crecemento Leather', 'Crecemento Sword, Crecemento Shield', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Musketeer', 'Musketeer [Character]', 'Musketeer', 'basic', '["coat"]', '["pistol","rifle"]', -65, -65, 'portrait', 50, 65, 50, 85, 30, 50, 1, 'Musketeer - Uses various firearms (both long and short range) to attack the enemy. Special skills include being able to fire a series of Pistol shots, and being capable of firing Sniper shots.', 'Crecemento Coat', 'Crecemento Rifle', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Scout', 'Scout [Character]', 'Scout', 'basic', '["leather"]', '["dag","rosario"]', -325, 0, 'portrait', 30, 70, 60, 70, 50, 50, 1, 'Scout - Restores HP to family members. They can use Healing stance to assist other family members, and also can use Daggers for close-range attacks.', 'Crecemento Leather', 'No Weapon', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Wizard', 'Wizard [Character]', 'Wizard', 'basic', '["coat"]', '["staff","rod"]', -195, 0, 'portrait', 30, 50, 40, 40, 75, 75, 1, 'Class that possess curse magic confusing enemy and aid magic helping friendly force. Air strike also possible. Big difference of performance possible to show, depends on how to use the aid magic.', 'Crecemento Coat', 'Crecemento Rod', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Aclla', 'Aclla [Character]', 'Aclla', 'cash', '["robe","coat"]', '["rod","staff"]', -1235, -130, 'portrait', 30, 60, 50, 60, 90, 50, 100, 'The day of defeat of Orden, God already knew Orden could resurrect some day and sealed own power deep inside of Occulta Fortress. And now the power of Orden is becoming powerful, a misterious woman, Aclla appeared from the deep inside of Occultal Fortress.', 'Experimental Robe', 'Experimental Rod', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Adelina', 'Adelina [Character]', 'Adelina', 'recruit', '["leather"]', '["sabre","pistol"]', -325, -260, 'portrait', 60, 80, 60, 60, 30, 50, 40, 'Adelina, a former pirate captain. She is looking for the traitor who killed her comrades on their way to the New Continent. She has average Attack but high Attack Speed. One of her stances allows her to use the sabre and pistol simultaneously.', 'Crecemento Leather', 'Crecemento Sabre', 'ASPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Adriana', 'Adriana [Character]', 'Adriana', 'recruit', '["leather","coat"]', '["sabre","pistol"]', -520, -585, 'portrait', 65, 65, 70, 50, 50, 50, 60, 'Daughter of a new noble in Vespanola. She became the youngest admiral due to her contribution in the Naval Battle and many other sea battle. She is dispatched for a special fleet for Castilla exploration.', 'Crecemento Leather', 'Crecemento Sabre', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Eileen', 'Aileen [Character]', 'Aileen', 'recruit', '["leather"]', '["lightbrac"]', -1365, -585, 'portrait', 30, 70, 60, 40, 85, 60, 100, 'A great thief taking Illier by storm. People think that she is rivals with White Wolf. However, they have actually been a team for a long time.  Everything about her is a mystery. No one knows her name, age, or where she came from.', 'Crecemento Leather', 'Crecemento Lightning Bracelet', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Aisha', 'Aisha [Character]', 'Aisha', 'cash', '["coat","robe"]', '["rod","staff"]', -1495, -585, 'portrait', 40, 50, 65, 40, 80, 70, 100, 'A water shaman found dormant in a lake of ancient Altria. Lada is said to have brought her out of the lake in order to chase Orden. She is extremely lazy and sluggish, something Aclla isn&amp;apos;t very fond of...', 'Experimental Coat', 'Experimental Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Aether', 'Aither [Character]', 'Aither', 'cash', '["coat"]', '["rifle"]', -1820, -325, 'portrait', 40, 70, 60, 90, 50, 40, 100, 'One of the five Astarte who serves the Star Guardian, Atlas. He survived a mysterious pirate attack when he was a child and grew up in Ailis as an orphan. Atlas, who carefully observed Aither&amp;apos;s excellent eyesight and his interest in gunfire and shooting, gave him a second life as an Astarte.', 'Experimental Coat', 'Experimental Bayonet', 'Accuracy', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Alejandro', 'Alejandro [Character]', 'Alejandro', 'recruit', '["leather","metal"]', '["gs","pole","jav"]', -195, -260, 'portrait', 90, 40, 70, 40, 30, 50, 60, 'Alejandro, a fisherman in Coimbra. He has once attempted to catch a giant octopus. He has a strong Attack and a large amount of HP. He favors Great Swords and Polearms.', 'Crecemento Metal', 'Crecemento Polearm', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Amy', 'Amy [Character]', 'Amy', 'recruit', '["coat"]', '["rosario","magscroll"]', -1105, -715, 'portrait', 30, 50, 60, 50, 70, 50, 100, 'The second daughter of the Marquis Illier Shausen, On a mission as a operation officer in the Illier State Department and is in activity as the chief of staff of the new warlord, &amp;apos;Evora&amp;apos; for the nation&amp;apos;s progress and change. She is not only sharp and smart but also has a fiery character.', 'Crecemento Coat', 'Crecemento Book', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Andre', 'Andre [Character]', 'Andre', 'recruit', '["leather","coat","robe"]', '["rap"]', -130, -195, 'portrait', 70, 60, 70, 60, 40, 50, 60, 'Mr. Andre Janzur the Designer, is the most famous designer in both the Homeland and the New Continent. He is also a well-rounded fighter whose choice of weapon is the rapier.', 'Crecemento Leather', 'Crecemento Rapier', 'Block', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Angelic', 'Angelic [Character]', 'Angelic', 'cash', '["robe","coat"]', '["xbow"]', -1885, -650, 'portrait', 50, 60, 45, 90, 50, 50, 100, 'Apprentice Judge from Calum Gradio of Armonia. She was handed over and raised by the church at the request of White Watcher who was both a best friend and a subject of judgment during the ordeal of the current Seraph at the time of Empyrium. She inherited the swiftness and strength of her parents - a White Watcher - along with powerful holy magic. For some reason, only a part of it can be used. She also bears a strong resistance to magic.', 'Experimental Coat', 'Experimental Crossbow', 'Immunity', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Angie', 'Angie [Character]', 'Angie', 'recruit', '["leather"]', '["hammer"]', -195, -520, 'portrait', 40, 60, 50, 60, 50, 50, 20, 'A niece of Jack, Angie is capable of Trap and Construction skills commands, but unable to attack normally.', 'Crecemento Leather', 'No Weapon', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ania', 'Ania [Character]', 'Ania', 'recruit', '["leather"]', '["blunt","tonfa"]', -325, -650, 'portrait', 60, 80, 60, 60, 40, 40, 80, 'Ania lost her parents in the explosion of Errac, and all that emotion and depression just turned inward. One day, a man came to Errac and said &amp;apos;Forgive me..&amp;apos;, and that instant her pent up sadness just burst forth. Years later, Ania and Nar became warriors of the town.', 'Crecemento Leather', 'Crecemento Blunt', 'ASPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Anies', 'Anies [Character]', 'Anies', 'recruit', '["robe"]', '["rosario"]', -975, -260, 'portrait', 40, 50, 45, 40, 85, 50, 100, 'Current Armonia Saint. Originally she was a normal girl but after Ornella had been dead, she became a Saint. A friend of Sirius and Cepheus.', 'Crecemento Robe', 'No Weapon', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Anita', 'Anita [Character]', 'Anita', 'recruit', '["coat"]', '["staff"]', -1950, -325, 'portrait', 40, 40, 60, 50, 80, 50, 100, 'Former product of Montoro and Truman&amp;apos;s bio-experiments, that somehow escaped from Truman&amp;apos;s underground laboratory. It attempts to clone Hamaan from Errac, but manages to clone only half of her, leaving a scar in itself. It then abandons its monster instincts and ego and takes on a human identity, giving herself the name Anita, which means &amp;apos;sweet and bitter&amp;apos;.', 'Crecemento Coat', 'Crecemento Staff', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ankita', 'Ankita [Character]', 'Ankita', 'cash', '["coat"]', '["rod"]', -1950, -260, 'portrait', 40, 40, 60, 50, 90, 55, 100, 'A monster created by Montoro and Truman&amp;apos;s experiments. After Montoro&amp;apos;s death, she was abandoned until Stratavista found her. She is used in Truman&amp;apos;s experiment under the name Type.3, and is named Ankita after it ends successfully. On their orders, she infiltrates Errac and succeeds in cloning Hamaan, but the sight of her fellow doppelganger&amp;apos;s suffering reminds her of her past. This causes her to betray Truman and head for the New Continent.', 'Experimental Coat', 'Experimental Rod', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Van2', 'Archbishop [Character]', 'Archbishop', 'cash', '["robe"]', '["magscroll"]', -1560, -650, 'portrait', 40, 50, 70, 50, 90, 40, 100, 'The man who is fighting hard to defend the Twisted Armonia from demise and save its people.', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Asoka', 'Asoka [Character]', 'Asoka', 'cash', '["leather","metal"]', '["sword","sabre","gs"]', -390, -650, 'portrait', 75, 75, 70, 50, 30, 50, 40, 'Mysterious swordwoman who came from far east island, to test the limits of sword skills. Cold-hearted and self-respecting Asoka never shows mercy to her enemies.', 'Experimental Metal', 'Experimental Great Sword', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Backho', 'Baek Ho [Character]', 'Baek Ho', 'recruit', '["leather"]', '["knuckle"]', -260, -585, 'portrait', 75, 75, 50, 50, 30, 50, 40, 'This enigmatic man works for a secret state organization in Coria. He displays immense intrigue in foreign affairs. Possesses the strength of the Hwoarang Spirits, which can increase his attack powers.', 'Crecemento Leather', 'Crecemento Knuckle', 'ATK to PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Bane', 'Bane [Character]', 'Bane', 'cash', '["leather"]', '["firebrac"]', -1040, -195, 'portrait', 40, 70, 55, 60, 80, 55, 100, 'A wandering bounty hunter, Since the notorious leader, Captain Bernardo has been dead, his subordinates scattered around living their own lives and Bane remained as a bounty hunter.', 'Experimental Leather', 'Experimental Fire  Bracelet', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('NatalieRare', 'Banshee Natalie [Character]', 'Banshee Natalie', 'cash', '["leather","coat"]', '["rifle"]', -1235, -325, 'portrait', 50, 65, 60, 90, 30, 60, 100, 'A commanding officer of the Illier army. During the time of the Rescue Knights, she fell into despair when Ophelia and Melissa, who died in order to save her and the citizens during the pioneering of the Snowfield area, were not recognized for their exploits. Later on, when the country became disturbed due to the civil war, she returned to the army and subdues the leaders of the civil war in order to overpower the corrupt aristocrats, who were busy taking their own interests...', 'Experimental Leather', 'Experimental Bayonet', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Barrel', 'Barrol [Character]', 'Barrol', 'recruit', '["coat"]', '["pistol"]', -650, -65, 'portrait', 50, 70, 60, 90, 30, 60, 100, 'He was a legendary soldier in Bristia. Currently retired and working a barber. He is heavy but moves unbelievably fast during battle.', 'Crecemento Coat', 'Crecemento Pistol', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('PanfiloBattle', 'Battle Cook Panfilo [Character]', 'Battle Cook Panfilo', 'cash', '["leather","metal"]', '["sword","sabre"]', -195, -455, 'portrait', 80, 50, 70, 40, 60, 50, 40, 'Panfilo de Narvaez, the talented chef of Cite de Reboldoeux aspires to conjure world-renowned dishes with ingredients from the New Continent. Reboldoeux is his first stop for his culinary experiments. He uses a sword and a Bracelet of Fire with the Flame-guard stance.', 'Experimental Metal', 'Experimental Sabre', 'SP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('IdgeBattle', 'Battle Smith Idge [Character]', 'Battle Smith Idge', 'cash', '["leather","metal"]', '["gs","pole","sword","shield"]', 0, -520, 'portrait', 70, 80, 60, 60, 30, 50, 40, 'Idge, Enhance Merchant of Cite de Reboldoeux. She was once simply an average woman, but was attracted by the exploration on the New Continent. She began enhancing armor after witnessing a person gets severely injured in battle. Her HP is lower than that of a Fighter, but she can wield the Polearm and Great Sword.', 'Experimental Metal', 'Experimental Polearm', 'ASPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('ClaudeY', 'Battlefield Claude [Character]', 'Battlefield Claude', 'accomplish', '["leather","metal"]', '["pole"]', -780, 0, 'portrait', 80, 60, 70, 50, 20, 50, 100, 'Claude Baudez during his golden years as a famous mercenary. He has a specialized combat style built around Polearms. His great combat skills are said to strike fear in his enemies.', 'Experimental Metal', 'Experimental Polearm', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Becky', 'Becky [Character]', 'Becky', 'cash', '["leather"]', '["icebrac"]', -1235, -585, 'portrait', 40, 75, 55, 55, 85, 50, 100, 'One of member of the Captain, Bernardo&amp;apos;s pirates. While she wandered around Granado Espada continent, she happened to meet Bane who were joining with pioneering families, and she also joined hands with the pioneering families because think it was good chance to make money.', 'Experimental Leather', 'Experimental Ice Bracelet', 'ASPD', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Bedel', 'Bedel [Character]', 'Bedel', 'recruit', '["coat"]', '["ibr"]', -1690, -390, 'portrait', 40, 60, 60, 90, 50, 40, 100, 'The lord of the current Bedel family. In recognition of his contribution in the 2nd Illier - Targa War, he became commander-in-chief of Illier. He always emphasizes the principles, but for the prosperity of his country, he takes whatever means he can.', 'Crecemento Coat', 'Crecemento Heavy Rifle', 'Physical Penetration', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Behemoth', 'Behemoth [Character]', 'Behemoth', 'cash', '["leather"]', '["firebrac"]', -65, -130, 'portrait02', 40, 30, 70, 30, 95, 80, 100, 'Being freed from Atlas after so long, Behemoth is confused to find himself in human form. However, as a former Light Demon, he watched how the owner of the star treated humans and began to develop an unexplainable curiosity about them. Now that Behemoth is living in human form, he begins to understand the existence of humans and ponders how to live his life in the future.', 'Experimental Leather', 'Experimental Fire  Bracelet', 'Magical Penetration', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Belith', 'Belith [Character]', 'Belith', 'cash', '["robe"]', '["elebrac","icebrac","lightbrac","firebrac"]', -1820, -650, 'portrait', 30, 40, 70, 60, 90, 50, 100, 'Existence of an abyss born in El Knatum, the underground of Armonia, beyond the rift. It once exercised the power of the deadly abyss by using the emotions of others as energy. Merely the form of this power barely remains in the present day, but these powers of Belith are still an unimaginable level of magic to ordinary people.', 'Experimental Robe', 'Experimental Special  Bracelet', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Grace', 'Bernelli [Character]', 'Bernelli', 'recruit', '["coat"]', '["pistol","rifle","shotgun"]', -260, -325, 'portrait', 40, 70, 40, 90, 30, 50, 40, 'Grace Bernelli, an Intelligence Officer from the Bristian Army. She is currently investigating what she believes to be a plot of Vespanola&amp;amp;. She has skills more advanced that those of Musketeers, and has a special stance for using Shotguns.', 'Crecemento Coat', 'Crecemento Shotgun', 'ASPD', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Berthe', 'Berthe and Charles [Character]', 'Berthe and Charles', 'recruit', '["coat","robe"]', '["staff","magscroll"]', -910, -650, 'portrait', 50, 60, 40, 50, 90, 50, 100, 'Memento Mori as Van&amp;apos;s shadow. She was supposed to be a saint but by the conspiracy of church, took her voice and expelled to underground. Afterwards, she became Memento Mori by the help of Van and got the ability to summon dead people and resist against darkness of Armonia. Charles that is the skull and accompanied by her all the time, speak things instead of her.', 'Crecemento Coat', 'Crecemento Staff', 'SP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Bianca', 'Bianca [Character]', 'Bianca', 'cash', '["coat"]', '["rifle"]', -1755, -390, 'portrait', 20, 70, 60, 90, 60, 40, 100, 'Currently a member of Kalbath and a bounty hunter, she seeks pleasure from planning to make the target trust her until the very last minute by truly caring and giving love, and then murder them ghastly.', 'Experimental Coat', 'Experimental Bayonet', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kano2', 'Blood Navy Kano [Character]', 'Blood Navy Kano', 'cash', '["robe"]', '["magscroll"]', -1235, 0, 'portrait', 40, 50, 55, 40, 85, 70, 100, 'Blood Navy the 1st Regiment Commander. After she failed to talk with the governor, in order to break the governor&amp;apos;s will and hold fast to her views, she returned to Blood Navy. She seems to always sensitive because of lots of works. It said whenever she meets the governor, there was a big or small arguments.', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('BLudin', 'Blue Flame Ludin [Character]', 'Blue Flame Ludin', 'cash', '["robe"]', '["firebrac"]', -910, 0, 'portrait', 40, 40, 50, 50, 90, 70, 100, '16-year-old Ludin. Without much effort, she can reach the level of making extreme temperature of blue flame.', 'Experimental Robe', 'Experimental Fire  Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Brigitte', 'Bridgette [Character]', 'Bridgette', 'cash', '["leather","metal"]', '["sword","sabre","rap"]', -1885, -65, 'portrait', 75, 75, 70, 60, 30, 50, 100, 'Amy&amp;apos;s older sister and the eldest daughter of the Shaussen family, who protects the east of Illier. She is the leader of the Shaussen family&amp;apos;s proud iron cavalry and specializes in hand-to-hand fight techniques that apply horsemanship.', 'Experimental Metal', 'Experimental Sabre', 'ASPD', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Brunie', 'Brunie [Character]', 'Brunie', 'recruit', '["coat"]', '["pistol"]', -195, -130, 'portrait', 40, 90, 40, 70, 30, 50, 40, 'Brunie Etienne, Treasure Hunter and Residential Manager of Cite de Reboldoeux. She possesses every Pistol stance and attacks enemies with high speed. She can use the exclusive skill Fatal Blues.', 'Crecemento Coat', 'Crecemento Pistol', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Bryan', 'Bryan [Character]', 'Bryan', 'recruit', '["leather"]', '["knuckle"]', -1040, -130, 'portrait', 90, 40, 70, 40, 50, 50, 100, 'In Iron Hammer Family, them men worked as a blacksmith from an early age, the only one who has the best skills have been inherited the ways of sacred weapons production. But the man who was going to be inherited the ways of sacred weapons production have been dead in Armonia 2nd Holy War, and as an exception, Bryan became to be inherited the crafting method.', 'Crecemento Leather', 'Crecemento Knuckle', 'STR', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CadetAdriana', 'Cadet Adriana [Character]', 'Cadet Adriana', 'cash', '["leather","coat"]', '["sabre","pistol"]', -585, -130, 'portrait', 70, 70, 60, 60, 40, 50, 60, 'When Adriana studied in the Navy Academy.', 'Experimental Leather', 'Experimental Sabre', 'Critical', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('AmyRare', 'Cadet Amy [Character]', 'Cadet Amy', 'cash', '["coat"]', '["rosario","magscroll"]', -1170, 0, 'portrait', 30, 50, 50, 50, 80, 50, 100, 'A cadet in &amp;apos;Illisia&amp;apos; military academy. She is used to embarrass other people around because of her freewheeling personality, but she is always the best in every training also. People usually call her as &amp;apos;Blonde Witch of Shausen&amp;apos;.', 'Experimental Coat', 'Experimental Book', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Elisa', 'Cadet Elisa [Character]', 'Cadet Elisa', 'cash', '["coat"]', '["rosario"]', -585, -195, 'portrait', 50, 30, 60, 50, 80, 50, 60, 'When Elisa studied in the Navy Academy.', 'Experimental Coat', 'Experimental Rosario', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CLeonele', 'Cadet Leonele [Character]', 'Cadet Leonele', 'cash', '["coat"]', '["pistol","rifle"]', -975, -195, 'portrait', 45, 80, 45, 80, 40, 50, 100, 'When Leonele studied in Vespanola Military Academy. He was a &amp;apos;Troublemaker&amp;apos;. He seemed to be wild, different from Adriana who has always been rational.', 'Experimental Coat', 'Experimental Pistol', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CadetRob', 'Cadet Rob [Character]', 'Cadet Rob', 'cash', '["coat"]', '["rifle"]', -1950, -390, 'portrait', 30, 70, 40, 90, 50, 50, 100, 'After losing his father to Sniper Bernelli, Rob hones his sniper skills with his partner &amp;apos;Johnny&amp;apos;, determined to avenge Bristia. When he fails to kill a single person on a mission, everyone doubts his abilities, but it is soon revealed that he deliberately misses his targets to inflict pain, making him a terror on the battlefield. Renauld enlists him in the Blood Navy, and he soon collapses. Rob is then scouted by Code Name J and joins Stratavista.', 'Experimental Coat', 'Experimental Bayonet', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kess', 'Caisse [Character]', 'Caisse', 'recruit', '["coat"]', '["pistol","rifle","ibr"]', -715, -325, 'portrait', 35, 80, 40, 75, 60, 50, 100, 'The new Governor of Bristia. He has succeeded to step forward for an independence of his country through his calculating acts. He has a special talent about using guns and also has understanding of various combat tactics.', 'Crecemento Coat', 'Crecemento Rifle', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Calyce', 'Calyce [Character]', 'Calyce', 'recruit', '["leather"]', '["xbow","dag"]', -325, -585, 'portrait', 50, 70, 50, 70, 30, 60, 60, 'Belongs to the second generation of the Granado Espada settlers. Orphaned at an early age, she wandered the streets of Auch, before being adopted by a secret organization. She became the youngest crossbow champion in the syndicate, at the age of fifteen. Calyce left the organization soon after, and established herself as a mercenary for hire. Her Eye of Cat scans and determines enemy weaknesses.', 'Crecemento Leather', 'Crecemento Crossbow', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('OrnellaBlack', 'Canna [Character]', 'Canna', 'cash', '["robe"]', '["rod","staff"]', -1625, 0, 'portrait', 30, 40, 60, 50, 95, 70, 100, 'The reflected image of the Savior seen through the Abyss Mirror, fueled by only its own desires and hatred. Despite this, it does not do anything that goes beyond the boundaries of morality.', 'Experimental Robe', 'Experimental Rod', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('ClairCN', 'Cannon Shooter Claire [Character]', 'Cannon Shooter Claire', 'cash', '["coat"]', '["cannon"]', -845, -195, 'portrait', 40, 60, 60, 80, 40, 50, 100, 'Claire at the age of 17; she has tried handling more graceful weapons but eventually chose a cannon. She learned how to handle the cannon by using the equipment called [Cartridge] through training in order to double the weapon&amp;apos;s power and speed.', 'Experimental Coat', 'Experimental Cannon', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Karmen', 'Carmen [Character]', 'Carmen', 'cash', '["coat"]', '["ibr"]', 0, -130, 'portrait02', 40, 50, 40, 90, 50, 70, 100, 'Born into poverty as a child, she was sponsored by the Medici family and received the best possible musical education. As an adult, her patronage was cut off for health reasons and she lived the life of a traveling artist until she met Rubiana, a young woman who had escaped from the imperial palace, and with her help she became one of Vespanola&amp;apos;s top stars. Just when things seem to be going so well for her, the curse of Mueletos arrives and her life begins to change yet again.', 'Experimental Coat', 'Experimental Heavy Rifle', 'DEX', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Cassandra', 'Cassandra [Character]', 'Cassandra', 'cash', '["metal"]', '["pole"]', -1560, -455, 'portrait', 80, 60, 80, 50, 40, 30, 100, 'Leader of the forces guarding Quiritatio. The arrival of Orden and the pioneers to Quiritatio opened her eyes to the concept of emotions and led her to the outside world.', 'Experimental Metal', 'Experimental Polearm', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CatherineREAL', 'Catherine [Character]', 'Catherine', 'recruit', '["coat","robe"]', '["pendant","rosario"]', -65, -260, 'portrait', 50, 50, 50, 50, 50, 80, 40, 'The daughter of Dr.Torsche. She died when she was just a child but Dr.Torsche created an automated robot to resurrect her. She can use the unique skill, Marionette.', 'Crecemento Coat', 'No Weapon', 'SEN', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CatherineDEX', 'Catherine (DEX) [Character]', 'Catherine (DEX)', 'recruit', '["coat"]', '["pistol","rifle","shotgun","sword","shield","blunt"]', -65, -260, 'portrait', 50, 50, 50, 80, 50, 50, 40, 'The daughter of Dr.Torsche. She died when she was just a child but Dr.Torsche created an automated robot to resurrect her (DEX). She can use most stances. She has the exclusive skill, Doll Dream.', 'Crecemento Coat', 'Crecemento Rifle', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CatherineINT', 'Catherine (INT) [Character]', 'Catherine (INT)', 'recruit', '["robe"]', '["firebrac","icebrac","lightbrac","elebrac","rod","staff","sword","shield","blunt"]', -65, -260, 'portrait', 50, 50, 50, 50, 80, 50, 40, 'The daughter of Dr.Torsche. She died when she was just a child but Dr.Torsche created an automated robot to resurrect her (INT). She can use most stances. She has the exclusive skill, Doll Dream.', 'Crecemento Robe', 'Crecemento Fire Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CatherineSTR', 'Catherine (STR) [Character]', 'Catherine (STR)', 'recruit', '["leather"]', '["sword","shield","rap","sabre","gs","pole","dag","blunt"]', -65, -260, 'portrait', 80, 50, 50, 50, 50, 50, 40, 'The daughter of Dr.Torsche. She died when she was just a child but Dr.Torsche created an automated robot to resurrect her (STR). She can use most stances. She has the exclusive skill, Doll Dream.', 'Crecemento Leather', 'Crecemento Sword', 'STR', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CatherineTorsche', 'Catherine Torsche [Character]', 'Catherine Torsche', 'recruit', '["leather"]', '["dag"]', -455, -325, 'portrait', 70, 80, 50, 50, 40, 50, 60, 'One and only daughter of Dr.Torsche. She was kidnapped by Hernandez, the secondary leader of Ten Nobles, and was presumed dead. She was brainwashed to be loyal to Duke Felipe, and raised as an assassin.', 'Crecemento Leather', 'Crecemento Dagger', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sesil', 'Cecille [Character]', 'Cecille', 'cash', '["coat"]', '["xbow"]', -845, -520, 'portrait', 40, 60, 60, 90, 40, 50, 100, 'Hunter hunting in the area around Armonia. She uses a bow as her main weapon. Her excellent ability to tame the beast as well as archery skills makes her certainly to knock the prey with &amp;apos;Grey&amp;apos;, her wolf domesticated for a long time.', 'Experimental Coat', 'Experimental Crossbow', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Charlotrare', 'Charlotte [Character]', 'Charlotte', 'recruit', '["leather","coat"]', '["firebrac"]', -1625, -65, 'portrait', 30, 70, 70, 40, 85, 50, 100, 'One of the masters of the Five Elements who was also known as the Star Keeper, the Master of Fire. She sought out to live amongst the pioneers, abandoning all she had inherited from the ancient god in order to experience the world.', 'Experimental Leather', 'Experimental Fire  Bracelet', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sherlin', 'Cherlyn [Character]', 'Cherlyn', 'recruit', '["robe"]', '["firebrac","magscroll"]', -650, -650, 'portrait', 40, 40, 45, 55, 80, 60, 100, 'She was under Hernandez&amp;apos; command and in charge of collecting unique phenomenon and items going through Granado Espada. She didn&amp;apos;t think to have a feud with Family, so she joined with them.', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('BerroniffRare', 'Chief Alchemist Veronif [Character]', 'Chief Alchemist Veronif', 'cash', '["coat","robe"]', '["magscroll"]', 0, -65, 'portrait02', 30, 40, 50, 50, 90, 80, 100, 'An alchemist from Illier, she was sent to Illisia to succeed Chief Alchemist Karin as she finalized her personal studies in Viron. She took her alchemy to the next level, utilizing alchemical techniques only allowed to the chief alchemist of the imperial court.', 'Experimental Robe', 'Experimental Book', 'Magical Penetration', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Chloe', 'Chloe [Character]', 'Chloe', 'cash', '["leather","coat"]', '["icebrac"]', -1755, -260, 'portrait', 30, 50, 60, 50, 95, 50, 100, 'One of the masters of 5 elements, who was once called the Master of Water and Star Arbiter. In the wake of the incident she experienced in Ailis, she enters the human race to see how the changed future of those who she punished goes.', 'Experimental Leather', 'Experimental Ice Bracelet', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Cristina', 'Christina [Character]', 'Christina', 'cash', '["leather","metal"]', '["cannon"]', -1690, 0, 'portrait', 50, 60, 60, 80, 40, 50, 100, 'Commander of Vespanola Special Force. She is sent to the chanceful land of Ailis with the commander of the legion, Valdoro, for inspection. However, it turns out her attention is all into exploring the munitions factory instead of the inspection...', 'Experimental Leather', 'Experimental Cannon', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Chungha', 'Chung Ha [Character]', 'Chung Ha', 'cash', '["leather"]', '["sword"]', -1625, -650, 'portrait', 70, 85, 60, 40, 40, 50, 100, 'A centurion of Coria Special Force. She lost her family to the bandits when she was young. The White Dragon took care of her since then and she enrolled to the special force. She learned how to listen and draw powers of the ghosts and become famous for her power.  She found unexpected information from a battlefield and started her journey to the New Continent to track the White Dragon for the truth...', 'Experimental Leather', 'Experimental Sword', 'Physical Penetration', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ciel', 'Ciel [Character]', 'Ciel', 'cash', '["leather"]', '["knuckle"]', -1300, -260, 'portrait', 70, 70, 75, 40, 40, 50, 100, 'The second daughter and the leader of Sainquis&amp;apos;s sisters who is a wanted person as S level from the mother country.A person who has injured her father in a childhood accident. At the moment of crisis, she is taken to the hands of a professional killer and passed on to fighting techniques using own whole body as his last disciple.', 'Experimental Leather', 'Experimental Knuckle', 'Damage from PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Infantry', 'City of Auch Infantry [Character]', 'City of Auch Infantry', 'recruit', '["leather","coat"]', '["rifle"]', -65, -520, 'portrait', 40, 50, 50, 80, 30, 50, 40, 'Soldier responsible for the security in Auch. He uses stances related to Rifles and has the unique skill, Concentration.', 'Crecemento Leather', 'Crecemento Rifle', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Clair', 'Claire [Character]', 'Claire', 'recruit', '["leather","metal"]', '["gs","cannon"]', 0, -650, 'portrait', 50, 80, 50, 60, 30, 50, 40, 'The second generation of Granado Espada settlers. Nobody knows of her origin, only that she was raised by different guardians during her childhood. Interested in trying her hand at everything, but has not particularly done well at anything.', 'Crecemento Metal', 'Crecemento Great Sword', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Claude', 'Claude [Character]', 'Claude', 'recruit', '["leather","metal"]', '["sword","sabre","gs","pole","blunt","jav"]', -195, -195, 'portrait', 80, 50, 80, 50, 30, 40, 60, 'Claude Baudez, the Weapons Merchant of Reboldoeux. The past few years were a hard for him, and he impresses many with the scars littering his face and his gruff voice. He can use many different weapons and has a higher HP than that of a Fighter.', 'Crecemento Metal', 'Crecemento Great Sword', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Coa', 'Coa [Character]', 'Coa', 'recruit', '["leather"]', '["knuckle"]', -1430, -585, 'portrait', 80, 60, 70, 50, 30, 50, 100, 'Survivor in the barren lands of the fallen civilization of ancient Altria. Her body became inhabited by the spirits of snakes after a cruel experiment by an ancient chief priest. She always ran on pure animal instinct, but a fateful encounter with a girl nicknamed the &amp;quot;Master of Fire&amp;quot; forced her to reconnect with her human side.', 'Crecemento Leather', 'Crecemento Knuckle', 'Decrease Skill DMG', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Chloe2', 'Code Name C [Character]', 'Code Name C', 'cash', '["leather","coat"]', '["icebrac"]', -1690, -650, 'portrait', 30, 50, 70, 50, 95, 50, 100, 'An ice magician and assassin who newly joined the Stratavista. Arrogant but manages to show sincerity to those who fear and awe herself.', 'Experimental Leather', 'Experimental Ice Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CodeNameJ', 'Code Name J [Character]', 'Code Name J', 'cash', '["leather","metal"]', '["cannon"]', -65, -325, 'portrait02', 40, 55, 70, 85, 40, 50, 100, 'Rescue Knights Captain Romina&amp;apos;s former classmate from the military academy. Jesus often clashed with Romina as a cadet but grew fond of her after Romina saved her from serious injury. When Romina joined the Rescue Knights and left for the New Continent, Jesus followed, drawn by both Romina and her fiance, who was also heading there. Upon arrival, she learned her fianc?was linked to Stratavista. Around the same time, a sorceress from Absinia, Black Lightning, recruited her as a Stratavista agent. Her first mission: investigate Orden - only to discover his connection to her fianc? setting her on a relentless pursuit.', 'Experimental Leather', 'Experimental Cannon', 'ATK', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Leona2', 'Code Name L [Character]', 'Code Name L', 'cash', '["leather"]', '["sword","sabre"]', -1105, -325, 'portrait', 90, 60, 75, 60, 30, 40, 100, 'When Leona worked in Stratavista, she did active work as a Code Name L, and it is said that she assassinated the ruling classes for each country with her silent and agile movement. She has focused on only her missions because she believed that it was the only way to fulfill &amp;apos;Bloody Revenge&amp;apos;.', 'Experimental Leather', 'Experimental Sabre', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Tora2', 'Code Name T [Character]', 'Code Name T', 'cash', '["leather"]', '["jav"]', -1755, 0, 'portrait', 55, 80, 50, 75, 40, 40, 100, 'The boy who gave up his father&amp;apos;s revenge and wished to live a happy life with Lisa. But people&amp;apos;s scorn and contempt for his past works and lack of his own social skills isolated him. When he turned 18, he commits murder at the cafe &amp;apos;Sea Elephant&amp;apos; and disappears.', 'Experimental Leather', 'Experimental Javelin', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Veatrice2', 'Code Name V [Character]', 'Code Name V', 'cash', '["coat"]', '["lightbrac"]', -1690, -455, 'portrait', 40, 40, 60, 50, 90, 60, 100, 'M&amp;apos;Boma&amp;apos;s biological sister from Absinia. In the battle against Code Name C she reaches the threshold of death but Absinia&amp;apos;s power, which was hidden within herself, is awakened. The power merges with the power of Tempest and brings out a new force of lightning.', 'Experimental Coat', 'Experimental Light Brc', 'Magical Penetration', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Trooper', 'Coimbra Trooper [Character]', 'Coimbra Trooper', 'recruit', '["leather","metal"]', '["sword","shield","pole","blunt"]', 0, -455, 'portrait', 50, 50, 80, 50, 30, 50, 20, 'A soldier in charge of the security in Port of Coimbra. He uses Sword and Polearm stances like Fighters. His power and speed is lower than that of Fighters, but he has higher HP and He can use the exclusive skill Provoke.', 'Crecemento Leather', 'Crecemento Sword, Crecemento Shield', 'Damage from Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('RioRare', 'Conductor Rio [Character]', 'Conductor Rio', 'cash', '["robe"]', '["lute"]', -1755, -65, 'portrait', 30, 50, 60, 40, 80, 80, 100, 'Rio, who has already gained fame throughout Orpesia for his musicality, now leads a band of his own. He returned to Granado Espada to reflect on himself, who had settled for a comfortable and luxurious life, and to cheer for the tired Pioneers again. He leads his band around the country, holding performances here and there.', 'Experimental Robe', 'Experimental Lute', 'Immunity', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('DiertrichRare', 'Consul Dietrich [Character]', 'Consul Dietrich', 'cash', '["leather"]', '["sword"]', -1170, -260, 'portrait', 80, 60, 70, 40, 40, 50, 100, 'Illier the 225th Consul. After she ended the war with the old warlord, Patrikyon, she was elected as a consul by full of support from the Illier people. She is managing the nation based on the idea of Machia , and since the civil war ended, is changing her concern to outside of the nation.', 'Experimental Leather', 'Experimental Sword', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Cruz', 'Cruise [Character]', 'Cruise', 'recruit', '["leather"]', '["sword"]', -520, -650, 'portrait', 80, 30, 70, 30, 60, 50, 60, 'A soldier staying in Castilla, he has a great ability yet he was not really recognized by others as he is obsessed over money. However, he does not really care about how others think about it.', 'Crecemento Leather', 'Crecemento Sword', 'Block', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('DariaRare', 'Crusader Daria  [Character]', 'Crusader Daria', 'cash', '["leather","metal"]', '["sword"]', -1365, -390, 'portrait', 90, 70, 80, 40, 30, 50, 100, 'Armonia Peacekeeping Forces, 1st Captain of ATX. Dispatched to the war-torn Royal Road of Illier to mediate between the two opposing factions. Known to be one of the only two people in Armonia capable of controlling Balisada, they are considered one of the region&amp;apos;s finest knights.', 'Experimental Metal', 'Experimental Sword', 'Physical Penetration', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('ClairCG', 'Cutie Claire [Character]', 'Cutie Claire', 'cash', '["coat"]', '["cannon"]', -845, -260, 'portrait', 40, 60, 60, 85, 40, 50, 100, 'Claire at the age of 17; she has tried handling more graceful weapons but eventually chose a cannon. She learned how to handle the cannon by using the equipment called [Cartridge] through training in order to double the weapon&amp;apos;s power and speed.', 'Experimental Coat', 'Experimental Cannon', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Daisy', 'Daisy [Character]', 'Daisy', 'cash', '["coat"]', '["xbow"]', -1235, -520, 'portrait', 20, 70, 50, 80, 50, 60, 100, 'The daughter of the Hunter Jaison. Daisy was born in Bedel Plain, She was used to get bored playing with her friends of the same age, she seems like having fool of curiosity and adventure spirit. She has learned hunting skills from hunters.', 'Experimental Coat', 'Experimental Crossbow', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Danev', 'Danev  [Character]', 'Danev', 'cash', '["leather","coat"]', '["dag"]', -65, -195, 'portrait02', 60, 75, 55, 75, 50, 30, 100, '&amp;quot;An honored one in the arid western lands. She is the eldest daughter of the Targa imperial family, always second to the crown prince, the first in line of succession. But when the crown prince, Samuel Targa, is murdered on the borderlands of Illier, everything changes for Danev.    &amp;quot;', 'Experimental Coat', 'Experimental Dagger', 'Critical Damage', 1, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Daria', 'Daria [Character]', 'Daria', 'recruit', '["leather"]', '["sword","rifle"]', -520, -520, 'portrait', 80, 65, 60, 60, 30, 50, 60, 'Daria bacame the youngest woman officer at 19. Since she lost her father at a young age, she always took care of younger sister. Worried about her sister who left for the new continent without saying anything, she took a long journey and came to new continent. When she was young because of the discrimination by men, she is hostile towards men.', 'Crecemento Leather', 'Crecemento Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Delfina', 'Delfina [Character]', 'Delfina', 'cash', '["leather"]', '[]', -1755, -650, 'portrait', 80, 60, 60, 60, 30, 50, 100, 'Once a child of Vespanola&amp;apos;s noble family who contributed to the war, she lost her family members due to the conspiracy of the Ten Nobles. While wandering the streets, Captain Bernardo took her into his ship. After the pirates were disbanded, she joins after hearing the news of Bane and Becky joining the pioneering family while collecting Ten Nobles&amp;apos; information.', 'Experimental Leather', 'Experimental Rapier', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Diluca', 'Deluca [Character]', 'Deluca', 'cash', '["robe"]', '["magscroll"]', -1820, -520, 'portrait', 40, 40, 60, 50, 90, 60, 100, 'A former librarian of Armonia and a wizard with the Forbidden Book of Distortion. After gaining the power of distortion from this Forbidden Book of Armonia, Deluca causes Hernandez&amp;apos;s &amp;quot;Time Recovered&amp;quot; and &amp;quot;Twisted Armonia&amp;quot; incidents and moves further away from the peaceful life she wanted. Deluca again notices an incident caused by herself and the power of distortion and visits the Family to prevent it.', 'Experimental Robe', 'Experimental Book', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Mi2', 'Designer Karjalainen [Character]', 'Designer Karjalainen', 'cash', '["leather"]', '["rap"]', -1755, -520, 'portrait', 80, 75, 60, 45, 30, 50, 100, 'Karjalainen, who sublimated the scars from public criticism into a new inspiration. A true designer now even recognized by Andre.', 'Experimental Leather', 'Experimental Rapier', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Diertrichherberthe', 'Dietrich [Character]', 'Dietrich', 'recruit', '["leather"]', '["sword"]', -1170, -195, 'portrait', 70, 60, 80, 40, 40, 50, 100, 'The head of Evora warlord and current Illier imperial guard commander. According to the idea of the past consul, Machia, she is trying hard to develop her country. She knows how to see the flow of the world, and how to manage people. She is praised as the best commander by Iller people.', 'Crecemento Leather', 'Crecemento Sword', 'STR', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('BryanRare', 'Divine Hammer Bryan [Character]', 'Divine Hammer Bryan', 'cash', '["leather","metal"]', '["knuckle"]', -1040, -65, 'portrait', 90, 50, 70, 40, 50, 50, 100, 'Bryan was the only female who participated in the Armonia 2nd Holy War, people who saw her used to mention that there were only spreading fragments of Abyss in the place where she passed away, for that reason, she became to be called Divine Hammer.', 'Experimental Metal', 'Experimental Knuckle', 'STR', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Dolores', 'Dolores [Character]', 'Dolores', 'cash', '["robe"]', '["lightbrac"]', -975, -650, 'portrait', 40, 50, 40, 40, 80, 70, 100, 'She is mademoiselle of the family, Ilie Baselrane, younger sister of twins. Now, she goes to a private school in Vespanola and is called a brilliant mind with a great brains and talent in her classroom, but because of her playful personality with no evil intention, she is used to make a trouble a lot. And In the place of those accidents, Hare is always with her.', 'Experimental Robe', 'Experimental Light Brc', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('bknight', 'Doom Slave [Character]', 'Doom Slave', 'cash', '["leather","metal"]', '["sword"]', -1430, -195, 'portrait', 80, 50, 85, 40, 40, 50, 100, 'Currently a berserker of Twisted Armonia, likely an Armonia Paladin in his past. For reasons unknown, he finds himself encroached by The Abyss&amp;apos; energy, attacking enemies indiscriminately.', 'Experimental Metal', 'Experimental Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Drachen', 'Drachen [Character]', 'Drachen', 'cash', '["leather","metal"]', '["sword","shield"]', -1950, 0, 'portrait', 70, 50, 100, 40, 40, 50, 100, 'The first Astarte and brother of Camiel. While he primarily uses the Power of Protection granted to him by Atlas, he can switch between offense and defense at will thanks to the spectacular swordsmanship he learned in the Katai Arena. Though he has been erased from his sister Camiel&amp;apos;s memory, he still secretly assists her from time to time by utilizing Atlas&amp;apos;s Power of Protection.', 'Experimental Metal', 'Experimental Sword', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Eduardo', 'Edward [Character]', 'Edward', 'recruit', '["leather"]', '["sabre","rap"]', 0, -585, 'portrait', 70, 70, 60, 50, 30, 50, 60, 'Having most of his memory wiped due to brutal experiments, he became one of the strongest Burlons in the cohort. He is said to have the power similar to the Nameless Person and the ability to summon a Grim-ripper.', 'Crecemento Leather', 'Crecemento Sabre', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('ElisaOfficer', 'Elisa [Character]', 'Elisa', 'recruit', '["coat"]', '["rosario"]', -585, -260, 'portrait', 50, 30, 40, 60, 90, 50, 60, 'She is a nurse officer in the 2nd fleet and helping lots of things to Castilla exploration. Lots of fleet soldiers are faithful with her.', 'Crecemento Coat', 'No Weapon', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Elizabeth', 'Elizabeth [Character]', 'Elizabeth', 'cash', '["robe"]', '["elebrac"]', -975, -455, 'portrait', 20, 50, 50, 60, 90, 70, 100, 'She became a famous painter of reputation for quite a young age. Because she don&amp;apos;t know much of the world yet, so, she don&amp;apos;t know well about her reputation, and she just paint hard due to be happy to see the look of people who love to see her pictures. Even if she already got many of great works, there are no less mess works that people would say &amp;apos;What the hell!&amp;apos;. It seems her talent is unstable according to her mood and physical condition.', 'Experimental Robe', 'Experimental Special  Bracelet', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ellie', 'Ellie [Character]', 'Ellie', 'cash', '["coat"]', '["ibr"]', -1885, -260, 'portrait', 50, 60, 50, 80, 60, 50, 100, 'Born an orphan, she was raised by Caisse. Despite her naive personality, she was taught by Bernelli to become a skilled sniper and a special forces officer. She was sent to Ailis and for the interests of Bristia.', 'Experimental Coat', 'Experimental Heavy Rifle', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ellie2', 'Ellie Craig [Character]', 'Ellie Craig', 'cash', '["coat"]', '["ibr"]', -1885, -325, 'portrait', 50, 60, 50, 80, 60, 50, 100, 'Ellie promoted to the senior officer through her various achievements and the push of Caisse. She was later given the surname Craig from Caisse, after the legendary sniper who played an essential role in the three-year war.', 'Experimental Coat', 'Experimental Heavy Rifle', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Emilia', 'Emilia Guliano [Character]', 'Emilia Guliano', 'recruit', '["coat"]', '["rod","rosario"]', -195, -325, 'portrait', 40, 50, 40, 50, 60, 60, 40, 'She is searching for her father. Her abilities include First-Aid and ESP, and her exclusive skill is &amp;apos;Healing.&amp;apos;', 'Crecemento Coat', 'Crecemento Rod', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('EmiliaSage', 'Emilia the Sage [Character]', 'Emilia the Sage', 'cash', '["coat"]', '["rod","rosario"]', -260, -455, 'portrait', 40, 50, 40, 50, 80, 60, 40, 'She is searching for her father. Her abilities include First-Aid and ESP, and her exclusive skill is &amp;apos;Healing.&amp;apos;', 'Experimental Coat', 'Experimental Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Judith', 'Empyrium Judith [Character]', 'Empyrium Judith', 'cash', '["leather","metal"]', '["pole"]', -1105, -585, 'portrait', 90, 50, 85, 50, 30, 50, 100, 'Her outstanding performance of missions leads to be a level 1 judge, Empyrium. Many judges admire her who is called &amp;apos;God&amp;apos;s judgement&amp;apos;.', 'Experimental Metal', 'Experimental Polearm', 'Damage from Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Anies2', 'Enforcer Anies [Character]', 'Enforcer Anies', 'cash', '["leather","metal"]', '["knuckle","armshield"]', -1430, -130, 'portrait', 80, 55, 80, 40, 40, 50, 100, 'The enforcer of twisted Armonia. Without the support of the pioneers who fell victim to Orden&amp;apos;s plans, Armonia faces its ultimate war. She lost two close friends in the war and is now lost as to where to go. Anger and hate are all that remains in her.', 'Experimental Metal', 'Experimental Knuckle, Experimental Armshield', 'STR', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Erica', 'Erica [Character]', 'Erica', 'cash', '["coat","robe"]', '["elebrac"]', -1950, -585, 'portrait', 60, 50, 50, 30, 90, 70, 100, 'Violante&amp;apos;s first doppelganger. While in the dungeon, Erica is found by the Family after Violante is sealed away, and she learns the news of her master, Violante. The Family tells Erica, who is hostile to them, the whole truth, and Erica joins the Family to find answers for herself. During this journey, she becomes mature after being torn between the master she followed and the family that defeated her master.', 'Experimental Coat', 'Experimental Special  Bracelet', 'Evasion', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sharon', 'Eva Sharon [Character]', 'Eva Sharon', 'recruit', '["coat"]', '["staff"]', -650, 0, 'portrait', 35, 60, 45, 50, 80, 50, 60, 'One of the ten nobles, Count Cortes&amp;apos; secretary. Very loyal to Cortes, and would do anything for him, even If blood is shed on one&amp;apos;s hands.', 'Crecemento Coat', 'Crecemento Staff', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Evil', 'Evil [Character]', 'Evil', 'recruit', '["coat","robe"]', '["lightbrac"]', -1105, -130, 'portrait', 40, 40, 50, 50, 90, 60, 100, 'Weapon itself in order to annihilate humanity, he was created with combining the ancient knowledge of Strata and technical skills of Truman. He looks like Kevin&amp;apos;s memory and knowledge who had strong body and managed magnetic fields well. But Kevin who had loved peace denied the body that was made so as to kill others, with occuring a big error in the main circuit system, he gave a huge damage to Stratavista and was sealed as a permanent freezing state.', 'Crecemento Coat', 'Crecemento Lightning Bracelet', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Violet2', 'Fenrir [Character]', 'Fenrir', 'cash', '["leather","metal"]', '["blunt"]', -1690, -260, 'portrait', 85, 40, 80, 50, 40, 50, 100, 'A member of [Centrion Wolf], Special Knights of the Eastern Front in Illier. Desiring for peace that will come one day, she is burning with will to protecting her country.', 'Experimental Metal', 'Experimental Hammer', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Freesia', 'Freesia [Character]', 'Freesia', 'cash', '["leather"]', '["sabre"]', -1950, -715, 'portrait', 90, 70, 50, 30, 40, 70, 100, 'The girl who lost everything due to the 3 Years War. Dying of starvation, Freesia was saved by Sido, the captain of the Vespanola 1st Fleet, and was given a life as a navy, but her innate freedom makes her unable to endure the rigid military life. Freesia inevitably deserts and lives as a &amp;apos;self-proclaimed pirate&amp;apos;.', 'Experimental Leather', 'Experimental Sabre', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Valkyrie', 'Freya [Character]', 'Freya', 'cash', '["leather"]', '["jav"]', -1625, -325, 'portrait', 80, 70, 60, 50, 40, 40, 100, 'The queen of Valkyrie, who once ruled Valkyries. It is said that she became a human due to some sort of incident and lost most of her memory and power.', 'Experimental Leather', 'Experimental Javelin', 'ALL RES', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Freeday', 'Friede [Character]', 'Friede', 'recruit', '["coat"]', '["lute"]', -650, -130, 'portrait', 40, 50, 50, 50, 80, 70, 100, 'Leader of a rookie band that currently is at no. 1 at Vespanolly charts. Decided to take a vaction for a while.', 'Experimental Coat', 'Experimental Lute', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Garcia', 'Garcia [Character]', 'Garcia', 'recruit', '["leather"]', '["pistol","rap"]', -130, -585, 'portrait', 60, 70, 60, 70, 30, 60, 60, 'Garcia hails from Bristia and was also the 2nd Lieutenant of the Bristia Special Army. Since he is under the impression that Edward was murdered by Montoro, he swears to take revenge for his brother by traveling to the New World. He is capable of using rapier-related skills. He also has the exclusive skill: Shadow Trigger.', 'Crecemento Leather', 'Crecemento Rapier', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Gaura', 'Gaura [Character]', 'Gaura', 'cash', '["leather"]', '[]', -65, 0, 'portrait02', 85, 55, 85, 45, 30, 50, 100, 'In ancient times, an Altrian, who battled the formidable Sea Demon Leviathan, saw her life dramatically transformed after an incident entangled her with both the Leviathan and a Chloe. Chloe&amp;apos;s curse compelled her to hunt sea demons endlessly, condemning her to a life adrift on the ocean. As she roamed the vast seas, she became the central figure in legends about a ghost ship haunting the dark waters. However, everything changed on the day known as &amp;apos;Fallen Star Day,&amp;apos; when she felt a profound shift within herself. Driven by this mysterious change, she bravely made landfall on Granado Espada.', 'Experimental Leather', 'Experimental Polearm', 'ATK to Monsters', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Giltine', 'Giltine [Character]', 'Giltine', 'cash', '["robe"]', '["elebrac"]', -1820, -130, 'portrait', 40, 40, 70, 50, 90, 50, 100, 'Goddess of Death and the ruler of the demons. Just before she was completely sealed by the Savior and Mulia in another world, she managed to reach the New Continent through an Abyss in the world of death. Her wings and power have withered out by using most of her authority as a Goddess to pass the Abyss. She has no choice but to cooperate with the Pioneers- who strangely resembles the Saviors of her own world- to get her powers back, but no one knows what she is exactly up to.', 'Experimental Robe', 'Experimental Special  Bracelet', 'Immunity', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Gracielo', 'Gracielo [Character]', 'Gracielo', 'recruit', '["leather"]', '["knuckle"]', -130, -455, 'portrait', 60, 70, 65, 50, 30, 50, 40, 'After the 3 Year War, Gracielo comes to Granado Espada and seeks for new adventures. He possesses High ATK SPD and Evasion, and adopts a fighting stance that is renowned for swift, lethal kicks.', 'Crecemento Leather', 'Crecemento Knuckle', 'AGI', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Grandies', 'Grandies [Character]', 'Grandies', 'recruit', '["leather","metal"]', '["sword","gs"]', -520, -260, 'portrait', 80, 60, 90, 50, 50, 30, 60, 'A clone of Grandma, the Pioneer Queen that is created as a result of endless experiment by Montoro.', 'Crecemento Leather', 'Crecemento Great Sword', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Grandma', 'Grandma [Character]', 'Grandma', 'recruit', '["leather","metal"]', '["gs"]', -65, -390, 'portrait', 70, 60, 90, 50, 30, 40, 60, 'Grandma, the Pioneer Queen. She gave up her wealth and honor and travelled to Ustiur from the Mainland. She has great power and high HP. She wields the Great Sword and she can use the exclusive skill &amp;apos;Highlander Soul&amp;apos;.', 'Crecemento Metal', 'Crecemento Great Sword', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Gurtrude', 'Grutrude [Character]', 'Grutrude', 'recruit', '["leather"]', '["knuckle"]', -65, -455, 'portrait', 70, 55, 70, 50, 30, 50, 40, 'Grutrude, who wants to investigate the mysteries of the New Continent, has just begun his mission. He has a strong Attack and high HP, especially for close-range battles where he can use his Knuckles to deal damage.', 'Crecemento Leather', 'Crecemento Knuckle', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ania2', 'Guardian Ania [Character]', 'Guardian Ania', 'cash', '["leather"]', '["tonfa"]', -1690, -65, 'portrait', 60, 85, 65, 40, 40, 50, 100, 'A guardian who came back to Errac after foreseeing the future of Errac from Quiritatio, the nexus of the ancient knowledge. The guardian is focused on defending the Errac from upcoming disaster.', 'Experimental Leather', 'Experimental Tonfa', 'AGI', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('CoaRare', 'Guardian Coa [Character]', 'Guardian Coa', 'cash', '["leather"]', '["knuckle"]', -1430, -650, 'portrait', 70, 80, 60, 50, 30, 50, 100, 'Guardian of a snake-worshipping clan of ancient Altria. She may be gentle and warm-hearted by nature, but she will not hesitate to destroy anyone who threatens the clan.', 'Experimental Leather', 'Experimental Knuckle', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('LooRare', 'Guardian Lu [Character]', 'Guardian Lu', 'cash', '["leather"]', '["crescent"]', -1560, 0, 'portrait', 85, 50, 75, 30, 30, 50, 100, 'Guardian of the Kepeluna, a clan that worships the bull. A man of innocent, easygoing nature, he enjoys protecting those weaker than him.', 'Experimental Leather', 'Experimental Crescent', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('NarRare', 'Guardian Nar [Character]', 'Guardian Nar', 'cash', '["leather","metal"]', '["crescent"]', -1690, -130, 'portrait', 80, 40, 100, 40, 30, 50, 100, 'Guardian Nar, who learned the combat skills of the Castilla tribe in Quiritatio, is committed to protecting Errac so that no one else will experience the disaster and the pain he has suffered due to [Fire Rhodolite].', 'Experimental Leather', 'Experimental Crescent', 'HP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Airheart', 'Harriot Airheart [Character]', 'Harriot Airheart', 'cash', '["leather"]', '[]', -1950, -520, 'portrait', 80, 60, 45, 50, 60, 55, 100, 'Captain of Leona&amp;apos;s private airship [The Vernie]. Harriot Airheart joined the Bristian army after graduating from the Vespanola Navy Academy but failed to distinguish herself due to her lack of combat skills. Recognizing her tactical prowess, however, Caisse appoints Airheart captain of the rebuilding Bristian Airship fleet. In the wake of the Quiritatio, political pressure from Vespanola forces her to take an undercover job with the Bristia Laboratory&amp;apos;s Civilian Aviation Corps, where she is appointed captain of Leona&amp;apos;s [The Vernie] and joins the Pioneering Family.', 'Experimental Leather', 'Experimental Sword', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Hass', 'Hass Laburd [Character]', 'Hass Laburd', 'recruit', '["leather","metal"]', '["gs"]', 0, -650, 'portrait02', 80, 55, 80, 50, 40, 40, 100, 'Second son of Katai&amp;apos;s powerful Laburd family. Consul Camiel Valkan&amp;apos;s soldier and adjutant. For years, he has been secretly investigating Katai&amp;apos;s scandals, and follows Camiel to Ailis when clues emerge there. However, due to a series of unexpected accidents there, Hass&amp;apos;s life faces a new phase...', 'Crecemento Leather', 'Crecemento Great Sword', 'DEF', 1, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Hektor', 'Hector [Character]', 'Hector', 'recruit', '["leather"]', '["sword","shotgun"]', -1170, -455, 'portrait', 75, 70, 55, 60, 40, 50, 100, 'Blood Navy officer. Becomes Blood Navy after graduating from military school. When Lenold died in battle, the Blood Navy civil war broke out and he acted with the pioneering family in order to settle it.', 'Crecemento Leather', 'Crecemento Sword', 'DEF', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Heka', 'Heka [Character]', 'Heka', 'cash', '["leather"]', '["knuckle"]', -1885, -455, 'portrait', 90, 70, 70, 40, 40, 50, 100, 'Around the time when Kirna felt that there wasn&amp;apos;t much more to be done finding clues about the Dragovan extermination in Pegadilla, she joined Burlon, a group that did not care about means and method. She worked under the name of Heka. There, she was able to fight with more freedom compare to Pegadilla and is also called as the &amp;apos;Mad Dog of Los Toldos&amp;apos; because of her rampage.', 'Experimental Leather', 'Experimental Knuckle', 'STR', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Hellena', 'Hellena [Character]', 'Hellena', 'recruit', '["robe"]', '["elebrac","firebrac","icebrac","lightbrac"]', -260, -715, 'portrait', 30, 30, 30, 45, 90, 75, 60, 'Hellena joined the sinister espionage organization of Duke Felipe for the sake of her ailing mother. She soared through the ranks with her inherent affinity for magic, and was eventually promoted to an assistant troupe leader. Will you help her achieve the future she deserves?', 'Crecemento Robe', 'Crecemento Fire Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Hermes', 'Hermes [Character]', 'Hermes', 'cash', '["coat"]', '["ibr"]', -1300, -325, 'portrait', 40, 60, 55, 80, 50, 60, 100, 'Hermes,the eldest of the Sainquis sisters, who is a fugitive in her country, has a notorious reputation for been a sniper. She is in conflict with Ciel because of her love for jewelry, but that does not sour their sisterly relationship. Venturing into the new continent with her two sisters in tow, she was confident that she could find a clue of her childhood there.', 'Experimental Coat', 'Experimental Heavy Rifle', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Heyran', 'Heyran [Character]', 'Heyran', 'recruit', '["coat"]', '["dag"]', -650, -195, 'portrait', 60, 70, 60, 60, 50, 50, 100, 'An ex-officer of Bristia Army. She now disguises as a Madame of the Red Hat, Bristia&amp;apos;s most fancy pub. She is popular with the customers for her carefree and composed personality.', 'Crecemento Coat', 'Crecemento Dagger', 'Damage from PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Hildegard', 'Hildegard [Character]', 'Hildegard', 'cash', '["leather"]', '["magscroll"]', -1625, -260, 'portrait', 30, 50, 70, 50, 90, 50, 100, 'Archbishop who has returned to position due to Archbishop Vega going missing. She is known to rule with an iron-fist and hence feared by the members of the church. Despite her reputation, she is a righteous woman who protects the weak.', 'Experimental Leather', 'Experimental Book', 'Immunity', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Idge', 'Idge Imbrulia [Character]', 'Idge Imbrulia', 'recruit', '["leather","metal"]', '["gs","pole"]', -260, -65, 'portrait', 60, 70, 60, 60, 30, 50, 40, 'Idge, Enhance Merchant of Cite de Reboldoeux. She was once simply an average woman, but was attracted by the exploration on the New Continent. She began enhancing armor after witnessing a person gets severely injured in battle. Her HP is lower than that of a Fighter, but she can wield the Polearm and Great Sword.', 'Crecemento Metal', 'Crecemento Great Sword', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Illusion', 'Illusion [Character]', 'Illusion', 'cash', '["leather"]', '["rap"]', -780, -520, 'portrait', 70, 70, 60, 50, 40, 60, 100, 'Another Guardian of Kielche who protect the dark and dangerous night street of Kielche. People who watched saying that it was like an fantastic magic show.', 'Experimental Leather', 'Experimental Rapier', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ion', 'Ion [Character]', 'Ion', 'recruit', '["robe"]', '["icebrac"]', -520, -715, 'portrait', 50, 30, 50, 30, 80, 70, 60, 'Son of Duke Felipe, the cousin of present Vespanola Queen. He was the student of Hernandez while he has grown up. However, he left his master to find the real reason of his life and move to the new continent.', 'Crecemento Robe', 'Crecemento Ice Bracelet', 'SP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Muathai', 'Irawan [Character]', 'Irawan', 'recruit', '["leather"]', '["knuckle"]', -130, -520, 'portrait', 80, 65, 50, 50, 30, 50, 60, 'A fighter from Ciam. He has strong power and high speed.', 'Crecemento Leather', 'Crecemento Knuckle', 'STR', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Isaac', 'Issac [Character]', 'Issac', 'cash', '["robe","coat"]', '["magscroll"]', -1755, -455, 'portrait', 30, 40, 55, 45, 90, 80, 100, 'Lord of Baselrane. Father of Dolores and Loraine, and brother to Joshua. He currently holds post as the Commander of Magic Corps.', 'Experimental Coat', 'Experimental Book', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ivy', 'Ivy [Character]', 'Ivy', 'cash', '["leather"]', '["firebrac"]', -1755, -585, 'portrait', 30, 40, 70, 30, 90, 80, 100, 'A chef from Bristia that shares happiness all over the world with her food. She has become a world-renowned chef by her efforts to break the prejudice that Bristian cuisine is tasteless.', 'Experimental Leather', 'Experimental Fire  Bracelet', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jd', 'JD [Character]', 'JD', 'recruit', '["leather"]', '["sword","sabre","rap","gs","blunt","crescent"]', -585, -650, 'portrait', 70, 60, 70, 60, 50, 40, 100, 'A member of a family of Knights that served Kielce for a long time. Due to an incident, he abandoned his name and country and joined Blood Navy. JD stands for Judgenment Day, his code name in Blood Navy.', 'Crecemento Leather', 'Crecemento Sabre', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jack', 'Jack [Character]', 'Jack', 'recruit', '["leather"]', '["pole","hammer"]', -260, -130, 'portrait', 50, 70, 50, 60, 40, 40, 20, 'Jack, the owner of the Reboldoeux Stone Pit. His multitude of scars shows that the effort he has put into maintaining his Stone Pit. He uses the Construction stance to assist other members, and possesses a strong Attack.', 'Crecemento Leather', 'Crecemento Polearm', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jaina', 'Jaina [Character]', 'Jaina', 'cash', '["coat"]', '["shotgun"]', -1170, -585, 'portrait', 30, 70, 55, 90, 50, 50, 100, 'A maid of Dr. Fernando Torsche. She had a name called Jane from the contribution of Three-Year War and became an imperial maid. but before long her name changed with Jaina when she returned to the Mansion of Dr.Torsch. Because of her  fiery character,  she always be with big or small accidents in the Mansion of Dr.Torsch.', 'Experimental Coat', 'Experimental Burst', 'ASPD', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jane', 'Jane [Character]', 'Jane', 'cash', '["coat"]', '["pistol"]', -910, -325, 'portrait', 20, 65, 55, 90, 60, 60, 100, 'The senior reporter of quite reputable paper, &amp;apos;Auch Standard Paper&amp;apos;. Though she is a woman, she has a nice skill of pistol and she made a lot of scoop with her outstanding reasoning power. She has really good memory for everything, but she still have a habit with memorizing always.', 'Experimental Coat', 'Experimental Pistol', 'DEX', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jin', 'Jin [Character]', 'Jin', 'cash', '["leather"]', '["dag"]', -910, -585, 'portrait', 80, 60, 65, 60, 40, 45, 100, 'A Ninja who came from the east with some mission. But nobody knows her purpose and she never tell that either. In truth, Asoka&amp;apos;s father and her father were the close friends and with this situation, she also was the close friend of Asoka and spent the childhood together.', 'Experimental Leather', 'Experimental Dagger', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Jose', 'Jose Corthasar [Character]', 'Jose Corthasar', 'recruit', '["leather","metal"]', '["pole","cannon"]', 0, -325, 'portrait', 50, 50, 50, 70, 50, 40, 60, 'Jose Corthasar, a veteran Cannon Trooper in the Port of Coimbra, where he is in charge of security. He has tried to manufacture gunpowder himself, because the Mainland did not provide the New World with gunpowder. He is the only character who can use the Cannon stance.', 'Crecemento Metal', 'Crecemento Cannon', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Joshua', 'Joshua [Character]', 'Joshua', 'recruit', '["robe"]', '["magscroll"]', -1300, -455, 'portrait', 30, 50, 55, 50, 85, 70, 100, 'Descendant of the Baselrane family and Deputy Commander of the Magic Corps. Joshua uses Golden Fireworks magic through her alchemy techniques. After finding herself involved in the civil war of get rid Illier, she is thinking of ways to get rid of her tedious tasks.', 'Crecemento Robe', 'Crecemento Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('JudithRare', 'Judith [Character]', 'Judith', 'recruit', '["leather","metal"]', '["pole"]', -1105, -520, 'portrait', 85, 50, 85, 50, 30, 50, 100, 'She abandoned her wealthy family and entered in the Armonian Order, then became a &amp;apos;Judge&amp;apos;. &amp;apos;Judge&amp;apos; is used to be called as a shadow of Armonia and a holy knight who is working missions secretly.', 'Crecemento Metal', 'Crecemento Polearm', 'HP Absorbation', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Yuliana', 'Juliana [Character]', 'Juliana', 'cash', '["coat"]', '["pistol","rosario"]', -1170, -65, 'portrait', 30, 70, 50, 90, 50, 50, 100, 'Lora Constans&amp;apos;s younger sister. She is a member of Armonia Crusaders. In 2nd Holy War, She carried out her miission that had to make spare time for the main force that retreated by Abyss army. Armonia main force was possible to retreat Apostadero safely but all of the defence forces was exterminated.', 'Experimental Coat', 'Experimental Pistol', 'Critical Damage', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kael', 'Kael [Character]', 'Kael', 'recruit', '["leather"]', '["sabre"]', -1365, -65, 'portrait', 75, 60, 75, 40, 40, 50, 100, 'Brother of Pei family, He is a representative of Gadapia Great Assembly. It&amp;apos;s not serious and hanging around always, but it seems like to prepare something.', 'Crecemento Leather', 'Crecemento Sabre', 'AGI', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kein', 'Kane [Character]', 'Kane', 'cash', '["leather"]', '["dag"]', -1755, -325, 'portrait', 85, 65, 55, 40, 40, 60, 100, 'A clown and dancer from the Arsene Circus. After the fall of the Arsene Circus, he moved to the New Continent to collect information about missing Emily with Sherry as a partner.', 'Experimental Leather', 'Experimental Dagger', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kano', 'Kano [Character]', 'Kano', 'recruit', '["robe"]', '["magscroll"]', -650, -390, 'portrait', 40, 50, 50, 60, 90, 60, 100, 'She was commissioned as an officer for the Bloody Navy despite her young age due to her special magic. In contrast to her flashy ability, she is careful and timid. She is quite mature for her age.', 'Crecemento Robe', 'No Weapon', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Karjalainen', 'Karjalainen [Character]', 'Karjalainen', 'recruit', '["leather","robe"]', '["rap"]', -325, -390, 'portrait', 60, 70, 50, 50, 70, 50, 60, 'She has a dream of being the best designer. She can use a rapier and magic.', 'Crecemento Leather', 'Crecemento Rapier', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kei', 'Kei [Character]', 'Kei', 'cash', '["leather","metal"]', '["jav"]', -1235, -650, 'portrait', 80, 70, 45, 50, 40, 50, 100, 'A warrior who escorted the first prophet, Lira before history was written. On the defeat day of Orden, he was sealed with Orden in the eternal prison. When Orden is liberated from the eternal prison, Kay also escaped the prison and comes to the east of the continent where Orden headed.', 'Experimental Metal', 'Experimental Javelin', 'ALL RES', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kevin', 'Kevin [Character]', 'Kevin', 'cash', '["coat","robe"]', '["lightbrac"]', -1105, -195, 'portrait', 40, 40, 50, 50, 90, 70, 100, 'Truman&amp;apos;s only son. In the similar period which Catherine was kidnapped, he finally died of a long illness caused by his weak body since he was born. He liked birds and flowers and loved peace. He always worried about his father&amp;apos;s science research for war. Particularly, he was interested in magnetic fields, so he was really good at managing magnatic fields.', 'Experimental Coat', 'Experimental Light Brc', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kirna', 'Kirna [Character]', 'Kirna', 'cash', '["leather"]', '["knuckle"]', -1885, -390, 'portrait', 90, 70, 70, 40, 40, 50, 100, 'A mercenary from the now extinct Dragovan. Prior to the clan&amp;apos;s extinction, she did not worship snakes and was unable to control her rampage frequently during combat. When she was out of control, she seriously injured and even killed many of her clan members, which eventually led to banishment. After she was banished, she wandered around and lived off by hunting until she met Brandine and moved to the New World to receive a higher level of education. She later found out that her clan had been destroyed, and is looking for clues in Pegadilla.', 'Experimental Leather', 'Experimental Knuckle', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kiss', 'Kiss [Character]', 'Kiss', 'cash', '["coat","robe"]', '["lightbrac"]', -1495, 0, 'portrait', 50, 50, 60, 50, 90, 50, 100, 'The second son of Vespanola&amp;apos;s Fluke family, famous for their proficiency in magic. Uses a unique stance called Electrica Villar, which combines his knowledge of traditional lightning magic and his love of billiards.', 'Experimental Coat', 'Experimental Light Brc', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Dietrich', 'Kurt [Character]', 'Kurt', 'recruit', '["leather"]', '["sabre","rap"]', -65, -585, 'portrait', 70, 70, 60, 50, 30, 50, 60, 'Kurt was a young commander leading the invincible legion during the Three-Year War. But, due to the discord with Lyndon, he became the leader of Burlons. He has high ATK skills and the ability to summon a Grim-ripper.', 'Crecemento Leather', 'Crecemento Sabre', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rada', 'Lada [Character]', 'Lada', 'cash', '["leather","metal"]', '["rod","staff"]', -1365, -715, 'portrait', 30, 60, 95, 50, 85, 30, 100, 'Wanders the world as head of the Direwolf mercenaries and earth shaman. After the return of Orden, she and Aclla both resumed their mission to take him down.', 'Experimental Leather', 'Experimental Staff', 'HP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rachel2', 'Lady Rachel [Character]', 'Lady Rachel', 'cash', '["coat","robe"]', '["pistol"]', -1365, -195, 'portrait', 20, 45, 55, 85, 80, 50, 100, 'The favorite daughter of the Sheffiled Family of Bristia. She has left on an adventure to find Ludin, whom she had loved since childhood.', 'Experimental Coat', 'Experimental Pistol', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Laval', 'Laval [Character]', 'Laval', 'cash', '["leather","metal"]', '["gs"]', -1885, -715, 'portrait', 90, 70, 80, 20, 50, 50, 100, 'After years of survival fueled by revenge and hatred, Laval decides to use the immense power he accidentally acquired to protect those he cares for.', 'Experimental Metal', 'Experimental Great Sword', 'Damage from PC', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rachel2Rare', 'Lead Manager Rachel  [Character]', 'Lead Manager Rachel', 'cash', '["coat","robe"]', '["pistol"]', -1365, -260, 'portrait', 20, 45, 55, 90, 80, 50, 100, 'Student Guardian of Student&amp;apos;s Council in Prestigious Private School. Transferred to Ludin&amp;apos;s private academy and joined the student council as her assistant in order to become closer to her.', 'Experimental Coat', 'Experimental Pistol', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Leona', 'Leona Vernier [Character]', 'Leona Vernier', 'recruit', '["leather"]', '["sword","sabre"]', -1105, -260, 'portrait', 85, 60, 75, 60, 30, 40, 100, 'Iiller no.1 master artisan, the only survivor in Vernier family. She likes roses and decorated her garden with full of roses, so people are used to call her as a rose artisan.', 'Crecemento Leather', 'Crecemento Sword', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Leonele', 'Leonele [Character]', 'Leonele', 'recruit', '["coat"]', '["pistol","rifle"]', -520, -130, 'portrait', 50, 80, 40, 80, 40, 50, 80, 'Elite officer from Vespanola. Currently working in Viron and a popular guy on the island. He has mastered military science, and is an expert in squad battle.', 'Crecemento Coat', 'Crecemento Rifle', 'HP Absorbation', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Leviathan', 'Leviathan [Character]', 'Leviathan', 'cash', '["robe"]', '["icebrac"]', -65, -260, 'portrait02', 35, 40, 65, 50, 95, 65, 100, 'The Sea Demon Leviathan, who once ruled the seas, sensed the end of the immortals had arrived. She sensed that her own moment of change was upon her, and though she resisted it, she could not defy its will. Eventually assuming human form, Leviathan wanders the world in search of a way to awaken the eggs, which have been unhatched for millennia.', 'Experimental Robe', 'Experimental Ice Bracelet', 'INT', 1, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Levin', 'Levine [Character]', 'Levine', 'cash', '["leather"]', '["sword"]', -780, -650, 'portrait', 80, 50, 70, 50, 60, 50, 100, 'A guardian of Montoro. Levine has a wound on his chest due to an incident before falling asleep in the deeper part of Lucifer Castle. One day, after waking up from the long sleep, Levine found Montoro in his child appearance and decided to protect him forever as being his sword.', 'Experimental Leather', 'Experimental Sword', 'HP Absorbation', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Viking', 'Lhote [Character]', 'Lhote', 'cash', '["leather","metal"]', '["blunt","sword","sabre"]', -715, -130, 'portrait', 80, 60, 75, 55, 30, 50, 100, 'He became a pirate admiring Adelina. He feels bored with the peaceful life after the Three-Year War so heads to the new continent to meet Adelina.', 'Experimental Leather', 'Experimental Axe', 'HP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lisa', 'Lisa Lynway [Character]', 'Lisa Lynway', 'recruit', '["leather"]', '["dag"]', 0, -260, 'portrait', 60, 80, 50, 60, 40, 40, 40, 'Lisa Lynway, the owner of the Sea Elephant Cafe in the Port of Coimbra. She is a charming lady, and is part of the second generation of Coimbrans. She uses a Dagger stance, and attacks with great speed. She has a high Critical Rate.', 'Crecemento Leather', 'Crecemento Dagger', 'ATK to PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Liung', 'Liung [Character]', 'Liung', 'recruit', '["leather"]', '["knuckle","lightbrac"]', -650, -585, 'portrait', 75, 50, 60, 30, 75, 50, 100, 'He was born to a father from Bristia and a mother from Dang. His combat style, improved from basic lightning magic which is inherited from his parents, is very unique and simple.', 'Experimental Leather', 'Experimental Knuckle', 'ALL RES', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Laura', 'Lora Constans [Character]', 'Lora Constans', 'recruit', '["coat"]', '["pistol"]', -845, -715, 'portrait', 40, 70, 50, 85, 40, 50, 100, 'Captain of the Armonia Guard to escort a high-ranking members including the Pope, Saint. Her Bullets receiving the Divine Protection deal a greater blow to evil followers. She was sweet and warm but she became to ignore everyone at a moment.', 'Crecemento Coat', 'Crecemento Pistol', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lorraine', 'Loraine [Character]', 'Loraine', 'cash', '["robe"]', '["elebrac"]', -975, -715, 'portrait', 40, 50, 40, 40, 90, 60, 100, 'She is mademoiselle of the family, Ilie Baselrane, older sister of twins. Comparing with Dolores, she&amp;apos;s got calm personality. She likes to have a tea time with Rev and Dolores together, but Dolores seems to have in mind of that. She is always used to sigh after clearing incidents from Dolores.', 'Experimental Robe', 'Experimental Special  Bracelet', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lorch', 'Lorch [Character]', 'Lorch', 'recruit', '["leather","coat"]', '["shotgun"]', -260, -390, 'portrait', 40, 60, 50, 80, 50, 50, 60, 'Lorch Furuhollen is a descendant of a distinguished Vespanolan family. He adores powerful firearms and has devoted himself to creating a powerful gun', 'Crecemento Leather', 'Crecemento Shotgun', 'Damage from PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Roreta', 'Loreta [Character]', 'Loreta', 'cash', '["leather"]', '["tonfa"]', -975, 0, 'portrait', 80, 65, 70, 45, 40, 50, 100, 'Without a regular job, she lives on rewards for treating all the requests about fight, protecting or getting rid of someone mainly around Coimbra.', 'Experimental Leather', 'Experimental Tonfa', 'STR', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Loo', 'Lu [Character]', 'Lu', 'recruit', '["leather"]', '["crescent"]', -1495, -715, 'portrait', 70, 50, 90, 30, 30, 50, 100, 'Descendant of the fallen civilization of ancient Altria, he now works under the Karima, the current rulers of Altria. Lu loves food and the intuitive rules of &amp;apos;survival of the fittest&amp;apos;.', 'Crecemento Leather', 'Crecemento Crescent', 'Damage from PC', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ludin', 'Ludin [Character]', 'Ludin', 'recruit', '["robe"]', '["firebrac"]', -520, -390, 'portrait', 40, 50, 40, 40, 90, 70, 60, 'The younger sister of Leonele, Ludin. She is a bit disrespectful since she is pampered but, her real personality is kind and shy. Come to new continent to meet her brother, Leonele, who did not see her for a long time.', 'Crecemento Robe', 'Crecemento Fire Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lynn', 'Lynn [Character]', 'Lynn', 'recruit', '["leather"]', '["gs"]', -1040, -260, 'portrait', 80, 60, 70, 40, 40, 50, 100, 'The knight family, Herberthe has protected Iiller imperial for generations, and she was a second daughter. She has passed the knight test only once and was the youngest one who got the Knighthood. After the canopy knight, she rushed the Vernier manor that would be called later as &amp;apos;Bloody Vernier&amp;apos;, saved a daughter of the Vernier and announced her name to the world.', 'Crecemento Leather', 'Crecemento Great Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lysette', 'Lysette [Character]', 'Lysette', 'cash', '["coat"]', '["pistol"]', -1820, -390, 'portrait', 40, 70, 50, 85, 50, 55, 100, 'One of the five Astartes who serves the Star Guardian, Atlas. Once a member of the Arzet family - a renowned family for their marksmanship - she was called a genius of Vespanola Military Academy. Her disappearance caused by a certain incident became the talk of Vespanola at the time. When Atlas saved Lysette from danger, her fate started a different path. She now lives a life of an Astarte after making a request to keep all her memories, good and bad.', 'Experimental Coat', 'Experimental Pistol', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('MBoma', 'MBoma [Character]', 'MBoma', 'recruit', '["coat","robe"]', '["staff","firebrac"]', -260, -260, 'portrait', 30, 30, 60, 40, 70, 70, 60, 'M&amp;apos;Boma, a wizard from Absinia who is interested in the New Continent. He can use cursing and fire magics with Staffs and Bracelets of Fire.', 'Crecemento Coat', 'Crecemento Staff', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Marchetti', 'Marchetti [Character]', 'Marchetti', 'recruit', '["coat","robe"]', '["rod","cube"]', -585, -715, 'portrait', 30, 40, 50, 90, 90, 65, 100, 'A genius scientist. With permission from Bristia Government General, he is working on his inventions in the Laboratory Zone. He has an elder sister.', 'Crecemento Coat', 'Crecemento Rod', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('MariaMayer', 'Maria [Character]', 'Maria', 'recruit', '["coat"]', '["pistol"]', -1690, -715, 'portrait', 30, 50, 75, 90, 50, 50, 100, 'A geologist from Bristia. As the Altria Pioneering Project started, she volunteered to be Marchetti&amp;apos;s assistant and is currently pioneering in Frourio.', 'Crecemento Coat', 'Crecemento Pistol', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Mary', 'Marie [Character]', 'Marie', 'recruit', '["coat"]', '["shotgun"]', -585, -455, 'portrait', 50, 70, 50, 85, 45, 50, 60, 'She is a daughter of the maid leader who worked for Dr.Torsche when he was in Vespanola', 'Crecemento Coat', 'Crecemento Shotgun', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('BertheRare', 'Mediator Berthe [Character]', 'Mediator Berthe', 'cash', '["robe"]', '["rod"]', -1430, -65, 'portrait', 40, 50, 55, 40, 85, 75, 100, 'Saint of twisted Armonia. Without the support of the pioneers who fell victim to Orden&amp;apos;s plans, Armonia faces its ultimate war. She remains hopeful and tries to gather those around her for the cause.', 'Experimental Robe', 'Experimental Rod', 'DEF', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('LorchRare', 'Meister Lorch [Character]', 'Meister Lorch', 'cash', '["coat"]', '["shotgun"]', -1755, -130, 'portrait', 30, 85, 60, 85, 40, 40, 100, 'A young man who doesn&amp;apos;t mind being expelled from his family for his own goal. Having mastered unique gun refining and manufacturing techniques while wandering the New Continent, he is also working on these skills for the pioneers in a private workshop established by Auch for him.', 'Experimental Coat', 'Experimental Burst', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Calyce2', 'Mercenary Calyce [Character]', 'Mercenary Calyce', 'cash', '["leather","coat"]', '["xbow"]', -1430, -390, 'portrait', 50, 70, 60, 90, 30, 50, 100, 'Head of the Pegadilla Mercenaries, said to have never failed a mission. Became the current leader of the mercenary group after the death of Gerad Loren.', 'Experimental Leather', 'Experimental Crossbow', 'DEX', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Meriel', 'Meriel [Character]', 'Meriel', 'cash', '["robe"]', '["lute"]', -1950, -65, 'portrait', 30, 50, 70, 40, 80, 80, 100, 'The second Astarte brought by Atlas and the spiritual leader of the Astarte. Meriel possesses the Power of Growth given by Atlas. The illegitimate daughter of the Illier&amp;apos;s Medici Family, she is known to have disappeared while being raised within the st.111 nursery. She is wary of going to areas other than the Sky Road and does not take missions that require her to leave the place but occasionally listens to the news of Ailis from Drachen.', 'Experimental Robe', 'Experimental Lute', 'Immunity', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Mertis', 'Mertis [Character]', 'Mertis', 'cash', '["robe"]', '["cube"]', 0, -715, 'portrait02', 60, 60, 60, 60, 60, 60, 100, 'A mysterious witch who appears to belong to Vespanola, but her free-spirited and alien behavior and personality make her feel out of place.', 'Experimental Robe', 'Experimental Cube', 'ATK', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Miha', 'Miha [Character]', 'Miha', 'cash', '["leather"]', '["elebrac"]', -1560, -195, 'portrait', 30, 70, 60, 50, 80, 50, 100, 'Descendant of the Taoist fox tribe from Mount Moonlight. Speaking to an old visitor of Godmother&amp;apos;s made him curious about the outside world. Now in the New World, he&amp;apos;s gathering experience as a mercenary.', 'Experimental Leather', 'Experimental Special  Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Miho', 'Miho [Character]', 'Miho', 'cash', '["coat"]', '["elebrac"]', -1560, -130, 'portrait', 30, 70, 50, 50, 90, 50, 100, 'Descendant of the Taoist fox tribe from Mount Moonlight. Headed West to find her escaped brother Miha and found herself in The Red Hat, the place where all knowledge gathers. It is unknown what will become of Miha once Miho finds him.', 'Experimental Coat', 'Experimental Special  Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Mireille', 'Mireille [Character]', 'Mireille', 'cash', '["leather"]', '["rap"]', -845, -390, 'portrait', 65, 50, 65, 40, 80, 50, 100, 'When she was in trouble in Armonia woods, the man in black hood helped her. After repeated training, she could finally get the ability to dexterously use a sword and goes on a journey to find him.', 'Experimental Leather', 'Experimental Rapier', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Misa', 'Misa [Character]', 'Misa', 'cash', '["coat"]', '["cannon"]', -1430, -455, 'portrait', 40, 50, 65, 85, 50, 50, 100, 'Truman&amp;apos;s first experiment and so-called prototype of Evil. Treasuring her sole memory of Evil, she destroyed Truman&amp;apos;s laboratory and came into the new continent...', 'Experimental Coat', 'Experimental Cannon', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Lobaselrane', 'Mistress Baselrane [Character]', 'Mistress Baselrane', 'cash', '["robe"]', '["elebrac"]', -1885, -195, 'portrait', 40, 50, 55, 40, 95, 65, 100, 'Lady Baselrane who returned to Illier after studying in the Vespanola Prestigious Private School. Unlike her twin sister Dolores, Loraine did not have much interest in joining the Magic Corps. She joined the Magic Corps nevertheless due to Issac&amp;apos;s suggestion to prove her abilities in the Corps for the family. Although she had natural-born talent that allowed her to use powerful, destructive magic, she ended up in second place after Dolores due to a lack of preparation.', 'Experimental Robe', 'Experimental Special  Bracelet', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('MontoroPC', 'Montoro [Character]', 'Montoro', 'accomplish', '["coat"]', '["rod","staff"]', -715, -715, 'portrait', 40, 40, 50, 50, 90, 70, 100, 'In the last moment, he moved his spirit to a new body that he had prepared earlier. His previous ambitions have disppeared by a certain reason but his evil mind still remains.', 'Experimental Coat', 'Experimental Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Moon', 'Moon [Character]', 'Moon', 'cash', '["coat"]', '["rifle"]', -1560, -520, 'portrait', 30, 50, 75, 90, 50, 50, 100, 'Burlon carries on the will of the Waltz brothers. He heads for the New World Altria in search of the Sainquis Sisters, carrying with him his Pocket Chain Watch and a rifle he received from the Waltz brothers.', 'Experimental Coat', 'Experimental Bayonet', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sharif', 'Najib Sharif [Character]', 'Najib Sharif', 'recruit', '["leather"]', '["rifle","sabre"]', -130, -325, 'portrait', 60, 70, 50, 70, 30, 50, 60, 'Najib Sharif, a merchant from Targa. He uses the Rifle and Sabre. He has fewer skills than the Musketeer, but greater Attack and Speed.', 'Crecemento Leather', 'Crecemento Rifle', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Nar', 'Nar [Character]', 'Nar', 'recruit', '["leather","metal"]', '["blunt","crescent"]', -260, -650, 'portrait', 80, 50, 80, 30, 30, 40, 80, 'No one in Errac knows his origins. He mysteriously showed up after the explosion. However, nothing escapes the spirit eyes of Hamaan. For some reason, after a conversation with her, he became a warrior to the protect the townspeople who saved him.', 'Crecemento Metal', 'Crecemento Blunt', 'HP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Natalie', 'Natalie [Character]', 'Natalie', 'recruit', '["leather"]', '["sword","rifle"]', -520, -195, 'portrait', 60, 65, 60, 80, 30, 60, 60, 'Natalie is confident about her older sister who studied the elite course and became a soldier, however, she also feels inferior because of which. Due to her feelings, she left her country and joined Rescue Knights in new continent.', 'Crecemento Leather', 'Crecemento Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Navas', 'Navas [Character]', 'Navas', 'cash', '["coat","robe"]', '["firebrac","icebrac","lightbrac","elebrac"]', -1495, -650, 'portrait', 40, 40, 50, 50, 90, 80, 100, 'Navas, a woman looking to take control of The Abyss. Her goal is to obtain the power of the human who defeated the ultimate devil.', 'Experimental Robe', 'Experimental Special  Bracelet', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Nena', 'Nena [Character]', 'Nena', 'recruit', '["leather"]', '["pole"]', -780, -390, 'portrait', 80, 70, 60, 50, 20, 50, 100, 'Last survivor of Vigilar tribe who protected for ages. Oneday after Lorenzo showed up in Bahamar, Vigilar tribe disappeard but meet Nena, the last Guardian of Forest in the mean time of solving the secret of 5 Elements.', 'Crecemento Leather', 'Crecemento Polearm', 'Damage from PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Neo10', 'Neo [Character]', 'Neo', 'basic', '["leather"]', '["sword"]', -1170, -130, 'portrait', 70, 60, 50, 50, 60, 50, 1, 'a Former Vespanola Warlock. In 3 years War, tried to save a comrade with controlling Focused Magic Canon but lost his right hand and all reputation and fall in despair. But recovered things by the help of friend and ahead to new continent to keep the promise with friends who expelled to new continent by the Reconquista policy.&lt;br&gt;You can create only one Neo character in Barrack.', 'Crecemento Leather', 'Crecemento Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Nicol', 'Nicole [Character]', 'Nicole', 'cash', '["leather","metal"]', '["crescent"]', -1820, -455, 'portrait', 90, 70, 70, 30, 30, 50, 100, 'Head of the assault squad of the Vespanolan Special Force, Legion. During a mission in Ailis, she and the assault squad received a &amp;apos;special treatment&amp;apos;, performed by Truman with Karin&amp;apos;s Knowledge, on Valdoro&amp;apos;s orders. Despite her usual belief - valuing self-discipline - Nicole gains power by drugs against her will. Nicole doesn&amp;apos;t want to use this new power but is torn between her belief as a person and her duty as a soldier.', 'Experimental Leather', 'Experimental Crescent', 'Decrease Skill DMG', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Nike', 'Nike [Character]', 'Nike', 'cash', '["leather","metal"]', '["blunt","shield"]', -1560, -585, 'portrait', 85, 55, 75, 30, 30, 50, 100, 'The last of the Paladins defending the Twisted Armonia, she fights against the Abyss Army fueled by her anger against the Abyss.', 'Experimental Metal', 'Experimental Hammer', 'Immunity', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Nina', 'Nina [Character]', 'Nina', 'cash', '["leather"]', '["sword"]', -1170, -520, 'portrait', 75, 70, 55, 60, 40, 50, 100, 'Blood Navy officer. When Lenold died in battle, the Blood Navy civil war broke out and he resolved the cirsis and controled the Blood Navy troops.', 'Experimental Leather', 'Experimental Sword', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Olivia', 'Olivia [Character]', 'Olivia', 'recruit', '["leather"]', '["dag","knuckle"]', -715, -195, 'portrait', 70, 80, 60, 50, 30, 50, 100, 'The Governor of Bristia, Caisse&amp;apos;s adjutant. Her real identity is a spy from Blood Navy in a command of Renauld. She was supporting Caisse behind to achieve her objectives. Since she can&amp;apos;t return to the troops because of some series of cases, she joins the family to achieve her objectives.', 'Crecemento Leather', 'Crecemento Dagger', 'ASPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ornella', 'Ornella [Character]', 'Ornella', 'cash', '["robe"]', '["rod","staff"]', -1560, -715, 'portrait', 30, 40, 60, 50, 90, 70, 100, 'The savior of Twisted Armonia. A man with the heart of gold who is watched over by god. He sets an example for people to follow and supports those around him in times of need. He can be found praying in the Cathedral.', 'Experimental Robe', 'Experimental Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Panfilo', 'Panfilo de Narvaez [Character]', 'Panfilo de Narvaez', 'recruit', '["leather"]', '["sword","sabre"]', -65, -130, 'portrait', 70, 50, 60, 40, 60, 50, 40, 'Panfilo de Narvaez, the talented chef of Cite de Reboldoeux aspires to conjure world-renowned dishes with ingredients from the New Continent. Reboldoeux is his first stop for his culinary experiments. He uses a sword and a Bracelet of Fire with the Flame-guard stance.', 'Crecemento Leather', 'Crecemento Sword', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Patrick', 'Patrick [Character]', 'Patrick', 'recruit', '["leather","metal"]', '["gs"]', -910, -455, 'portrait', 80, 40, 70, 50, 50, 50, 100, 'Patrick is the same age as William, Commander of the Crusaders is. He has not grown old since his left arm was sealed. He belonged to Memento Mori Crusaders before, but while St. Ornella is fixing his arm, he is a member of Armonia Crusaders. Patrick was missing in the 2nd Armonia sacred war and returned with changed appearance.', 'Crecemento Leather', 'Crecemento Great Sword', 'HP Absorbation', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Grandies2', 'Pioneer Queen Grandma [Character]', 'Pioneer Queen Grandma', 'accomplish', '["leather","metal"]', '["gs"]', -650, -260, 'portrait', 70, 60, 100, 50, 40, 40, 100, 'A portrait of Grandies when she was pioneering in the front line while she left Claire with Claude. People praised her calling her Pioneer Queen.', 'Experimental Metal', 'Experimental Great Sword', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('AdelinaPirate', 'Pirate Adelina [Character]', 'Pirate Adelina', 'cash', '["leather"]', '["sabre","pistol"]', -130, -260, 'portrait', 70, 90, 60, 60, 30, 60, 60, 'Adelina, a former pirate captain. She is looking for the traitor who killed her comrades on their way to the New Continent. She has average Attack but high Attack Speed. One of her stances allows her to use the sabre and pistol simultaneously.', 'Experimental Leather', 'Experimental Sabre', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Psyche', 'Psyche [Character]', 'Psyche', 'cash', '["robe"]', '["staff"]', -1820, -195, 'portrait', 50, 60, 40, 50, 90, 60, 100, 'A girl whose origin is unknown. Four years ago, she was bereaved of the person who raised her, an orphan, for an unknown reason. Most of her past memories gone and slowly dying from loss and loneliness, she met We&amp;apos;d, a bird with the mysterious power of bringing the souls together. We&amp;apos;d taught Psyche how to use the soul magic and to communicate with people, but it still seems difficult for her to communicate with people other than spirits.', 'Experimental Robe', 'Experimental Staff', 'SP Recovery', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Joshua2', 'Queen Cerny Joshua [Character]', 'Queen Cerny Joshua', 'cash', '["robe"]', '["magscroll"]', -1300, -520, 'portrait', 30, 50, 60, 50, 85, 65, 100, 'Winner of Illier&amp;apos;s 420th Ball. For her stage performance, she used her renown Golden Fireworks technique. That is the name she became known for after defeating the Black Scorpion mercenaries and thwarting their invasion plans.', 'Experimental Robe', 'Experimental Book', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rachel', 'Rachel Sheffield [Character]', 'Rachel Sheffield', 'cash', '["robe"]', '["pistol"]', -715, -585, 'portrait', 20, 40, 50, 75, 85, 60, 100, 'She is a senhorita of the upper class of Bristia and a best friend of Ludin&amp;apos;s. She travels to the new continent to find Ludin. Her beautiful Illusion Gunner uses a pistol and a magic scroll.', 'Experimental Robe', 'Experimental Pistol', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rakicia', 'Rakicia [Character]', 'Rakicia', 'cash', '["robe"]', '["gs"]', -1820, -585, 'portrait', 75, 50, 65, 50, 60, 50, 100, 'The Great Warrior of Absinia. Rakicia, a Great Warrior full of ambition, succeeds in becoming a wizard as well as a warrior during her journey to seek honor. Rakicia now joins the Family to also gain honor in the New Continent as well.', 'Experimental Robe', 'Experimental Great Sword', 'SP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ralph', 'Ralph [Character]', 'Ralph', 'cash', '["leather"]', '["xbow"]', -520, -455, 'portrait', 50, 70, 60, 90, 30, 50, 60, 'Ralph is an Intelligence Officer from Vespanola who was dispatched to investigate a situation in the new continent.', 'Experimental Leather', 'Experimental Crossbow', 'Accuracy', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ramiro', 'Ramiro [Character]', 'Ramiro', 'recruit', '["leather"]', '["sword","dag"]', 0, -130, 'portrait', 60, 80, 40, 50, 40, 50, 20, 'Second generation of the new continent settlers. An immature and cheeky boy, with a selfish personality. Weak against the strong and strong against the weak. His overall stats are low due to his small size, but has very high agility. He holds a dagger in his one-handed sword stance and a normal sword in his greatsword stance.', 'Crecemento Leather', 'Crecemento Sword', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Racel', 'Rascel [Character]', 'Rascel', 'cash', '["leather"]', '["sabre","dag"]', -585, -390, 'portrait', 70, 75, 65, 60, 30, 50, 60, 'He is royal family of Targa but not related with succession of throne. His family work is trade between Orpesia and Targa. He is willing to take a tough job although pampered while growing up as a son of royal family and wealthy merchant. His face and speaking looks like ignoring others but he is a man who knows how to respect skillful person.', 'Experimental Leather', 'Experimental Sabre', 'Damage from Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Raven', 'Raven [Character]', 'Raven', 'recruit', '["leather"]', '["rap","pistol"]', -455, -650, 'portrait', 70, 70, 60, 70, 30, 50, 60, 'A butler for Lucifer castle of Montoro, who worked as a spy officer for Bristia but was caught by Montoro after the Three-Year War and now works for him. He has strong animosity towards Montoro, but he looks like he is satisfied with his work.', 'Crecemento Leather', 'Crecemento Pistol', 'Critical', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sariel2', 'Reaper Sariel [Character]', 'Reaper Sariel', 'cash', '["robe"]', '["cube"]', -1105, -455, 'portrait', 45, 35, 60, 70, 95, 50, 100, 'Sariel&amp;apos;s only goal is &amp;apos;Enemy annihilation&amp;apos;. Wearing armors that made by people&amp;apos;s bones and souls which he killed, and he goes around battle fields.', 'Experimental Robe', 'Experimental Cube', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rebecca', 'Rebecca [Character]', 'Rebecca', 'cash', '["coat"]', '["pistol"]', 0, 0, 'portrait02', 20, 40, 40, 40, 90, 70, 100, 'A genius scientist who rivals Marchetti when it comes to chemistry and biology. But before her reputation can take hold, she is scouted by Truman and becomes his assistant. Threatened by the recent events on Ailis and the appearance of strangers, she develops a special biochemical bullet to protect herself and her research.', 'Experimental Coat', 'Experimental Pistol', 'Damage from Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('EmiliaLunatic', 'Reckless Emilia [Character]', 'Reckless Emilia', 'recruit', '["coat"]', '["rod","staff"]', -390, -715, 'portrait', 30, 60, 30, 55, 85, 65, 60, 'Emilia, who excessively tested the power of constellation, awakened the dark side of her soul, which had been dormant for the last 20 years. What will she do in the chaotic continent, with her reckless desires in full manifestation?', 'Crecemento Coat', 'Crecemento Rod', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('RescueKnight', 'Rescue Knight [Character]', 'Rescue Knight', 'recruit', '["leather","metal"]', '["sword","rifle"]', -195, -390, 'portrait', 60, 60, 50, 70, 30, 50, 60, 'The Rescue Knights are a neutral force that protects and aids injured pioneers. They use Defending Guard and Defending Shot stance.', 'Crecemento Metal', 'Crecemento Sword', 'Damage from Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('RominaRare', 'Rescue Officer Romina [Character]', 'Rescue Officer Romina', 'cash', '["coat","leather"]', '["rifle"]', -1625, -195, 'portrait', 40, 60, 60, 85, 40, 55, 100, 'Romina when she was a cadet. A model-cadet to both her peers and juniors at the academy. She tends to take a more supportive role as a cadet rather than fight in the forefront of the battle.', 'Experimental Leather', 'Experimental Bayonet', 'Immunity', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kess2', 'Resistance Caisse [Character]', 'Resistance Caisse', 'cash', '["coat"]', '["rifle","pistol","xbow","shotgun","ibr"]', -1625, -520, 'portrait', 35, 80, 40, 75, 60, 50, 100, 'After a crushing defeat in a battle for Bristia&amp;apos;s independence, Caisse&amp;apos;s support base has been drastically weakened. Caisse tries desperately to develop technology after the war, while JD has rather different opinions concerning independence. The two determine to go their separate ways.', 'Experimental Coat', 'Experimental Bayonet', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Heyran2', 'Resistance Heyran [Character]', 'Resistance Heyran', 'cash', '["leather"]', '["dag"]', -1625, -585, 'portrait', 80, 60, 70, 40, 40, 50, 100, 'She lost everything she had on the last battle of the Independence War. Her country, peers, and herself. She became one of JD&amp;apos;s hawks when Resistance got divided and now is sustaining herself with the great cause of independence and personal vengeance assassinating main figures of Blood Navy.', 'Experimental Leather', 'Experimental Dagger', 'Damage from PC', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('JD2', 'Resistance JD [Character]', 'Resistance JD', 'cash', '["leather"]', '["sword","sabre","rap","gs","blunt","crescent"]', -1625, -455, 'portrait', 85, 65, 75, 45, 40, 40, 100, 'JD loses everything by the hands of the Blood Navy after the defeat in the battle for Bristia&amp;apos;s independence. He establishes a resistance group with Caisse and others who had scattered after the last battle. However, the resistance eventually breaks in half with each leader having their own agenda. JD prepares to emancipate Bristia in his way with his comrades.', 'Experimental Leather', 'Experimental Crescent', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rio', 'Rio [Character]', 'Rio', 'recruit', '["robe"]', '["lute","lightbrac"]', -195, -585, 'portrait', 40, 50, 40, 40, 80, 70, 60, 'Auch Enhance Merchant Vicente Rio. Once a reclusive poet, he now basks in humanity. A strikingly young gentleman from Bristia who appears to hail from the second generation New World settlers. Vicente rarely reveals his inner self. The familiarity of his name suggests Auch heritage.', 'Crecemento Robe', 'Crecemento Lightning Bracelet', 'Decrease Skill DMG', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Risky', 'Risky [Character]', 'Risky', 'cash', '["robe"]', '["elebrac"]', -1105, -650, 'portrait', 20, 60, 50, 50, 80, 60, 100, 'One of many descendants of the head of Arsene. She was an orphan, the head of Arsene adaopted her and gave her name, Risky. Her main mission was a stealing information from high class ministers. So she couldn&amp;apos;t use weapons during her missions, that was the reason she learned the card magic from the head of Arsene.', 'Experimental Robe', 'Experimental Special  Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('RobClemens', 'Rob Clemens [Character]', 'Rob Clemens', 'recruit', '["coat"]', '["rifle"]', -1950, -455, 'portrait', 30, 70, 40, 80, 50, 50, 100, 'After losing his father to Sniper Bernelli, Rob tries to force his way into Kielce in revenge for Bristia, but is thwarted by Stratavista. He is captured by Violakea and sent back to homeland, where he joins the Stratavista. In 1540, he receives a secret order and begins to search for Truman&amp;apos;s doppelganger, but gradually realizes Stratavista&amp;apos;s true identity.', 'Crecemento Coat', 'Crecemento Rifle', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Romina', 'Romina [Character]', 'Romina', 'recruit', '["leather","metal"]', '["rifle","sword"]', -130, -130, 'portrait', 70, 60, 70, 70, 40, 50, 60, 'Captain Romina of Rescue Knights in Ustiur. She was born in the New Continent and is dissatisfied with the Mainland. She can use Defending Guard and Defending Shot stances with a sword and a shield. she can use the exclusive skill Resuscitation.', 'Crecemento Metal', 'Crecemento Sword', 'Damage from PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ronera', 'Ronera [Character]', 'Ronera', 'cash', '["coat"]', '["rifle"]', -65, -390, 'portrait02', 30, 55, 40, 95, 70, 60, 100, 'Framed for possession and abandoned by her family, Ronera was sold into marriage. She tried to accept the life that she never asked for, as she deemed it better than being framed a monster by her own kin, but that life also came to a close when her husband was killed by a group of mysterious killers, in the broad daylight no less. After her husband was murdered by mysterious killers, the group, Kalbath, witnessed her speaking to his spirit and recruited her. Tasked later with eliminating the Klein family, she couldn&amp;apos;t kill the last survivor-a young girl who reminded her of herself-and chose to flee with her instead.', 'Experimental Coat', 'Experimental Bayonet', 'ATK to Monsters', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rosa', 'Rosa [Character]', 'Rosa', 'recruit', '["coat"]', '["lute"]', -715, -650, 'portrait', 40, 50, 50, 40, 80, 70, 100, 'She was singing at night time about missing her home town and she suddenly met someone that her song cured him, so she decided to sing for the tired people to give brave and hope.', 'Experimental Coat', 'Experimental Lute', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Spirit', 'Rose, The Spirit [Character]', 'Rose, The Spirit', 'recruit', '["robe"]', '["elebrac"]', -715, -455, 'portrait', 30, 40, 60, 40, 90, 70, 100, 'A Homunculus that Montoro made with Rose as a medium. After the death of Montoro, to know the reason why she exists, she started to be with the Pioneer Family.', 'Experimental Robe', 'Experimental Special  Bracelet', 'Damage from Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Rosie', 'Rosie [Character]', 'Rosie', 'cash', '["leather"]', '["sword"]', -1820, -260, 'portrait', 80, 60, 70, 50, 50, 50, 100, 'Drawn by Rosie&amp;apos;s positive and bright mindset even in a chaotic battlefield, Stella takes her with herself to a small country in the East. When Rosie became of age, she asks Stella for some favor and shares her power to travel to the New Continent.', 'Experimental Leather', 'Experimental Sword', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('DelfinaRare', 'Royal Guard Delfina [Character]', 'Royal Guard Delfina', 'cash', '["leather"]', '[]', -1755, -715, 'portrait', 85, 60, 60, 60, 30, 50, 100, 'A member of Vespanola&amp;apos;s noble family who contributed to the war. She learned swordsmanship from an early age due to her father&amp;apos;s contribution to the war and is very proud of the family&amp;apos;s swordsmanship. In a sword match held by the royal family, she overpowered all the knights of considerable skill and started to be called the Flash Delfina.', 'Experimental Leather', 'Experimental Rapier', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('EileenRare', 'Rubiana [Character]', 'Rubiana', 'cash', '["robe"]', '["lightbrac"]', -1365, -650, 'portrait', 30, 50, 55, 40, 90, 80, 100, 'Princess of Illier and 1st in the line of succession.', 'Experimental Robe', 'Experimental Light Brc', 'Cast Time', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SakuraRare', 'Sakura [Character]', 'Sakura', 'cash', '["leather"]', '["pole"]', -1495, -455, 'portrait', 75, 60, 80, 50, 30, 50, 100, 'Youngest daughter of the [Yoshino], a noble family from the Island Nation of the Far East. Yearning to become a warrior, she escaped to the New Continent without telling her father.', 'Experimental Leather', 'Experimental Polearm', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sakura', 'Sakura Hime [Character]', 'Sakura Hime', 'cash', '["leather"]', '["pole"]', -1495, -390, 'portrait', 80, 60, 80, 50, 30, 50, 100, 'Youngest daughter of the [Yoshino], a noble family from the Island Nation of the Far East. She is graceful and elegant, much like a cordial princess.', 'Experimental Leather', 'Experimental Polearm', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sariel', 'Sariel [Character]', 'Sariel', 'recruit', '["robe"]', '["cube"]', -1105, -390, 'portrait', 45, 35, 60, 70, 90, 50, 100, 'He is a priest working in secret agencies directly under the Armonia Pope. It said that his combat skills on the basis of strong faith is the same as a reaper.', 'Crecemento Robe', 'Crecemento Cube', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Scarlet', 'Scarlet [Character]', 'Scarlet', 'cash', '["coat","leather"]', '["dag"]', -1300, -195, 'portrait', 90, 50, 40, 60, 40, 60, 100, 'The youngest among three of Sainquis sisters who are raging in the country. It said that she have commited murder with talking to her doll, Candy. that she was always holding in her arms.', 'Experimental Leather', 'Experimental Dagger', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Yeganeh2', 'Scavenger Yeganeh [Character]', 'Scavenger Yeganeh', 'cash', '["leather"]', '["gs"]', -1300, -650, 'portrait', 90, 50, 75, 55, 40, 50, 100, 'The group that controls the crime of the Orpesia continent, First-rate killer of [Kalbath]. It is called a Scavenger who has worked for decades as a lawless man without blood or tears, and changed the lives of people to money.', 'Experimental Leather', 'Experimental Great Sword', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Selane', 'Selene [Character]', 'Selene', 'recruit', '["robe"]', '["icebrac"]', -715, -520, 'portrait', 30, 50, 40, 50, 80, 70, 100, 'One who used to be a maid of Novia. But because of Selene&amp;apos;s ineptitude, Novia threw her out and turned her into an ice sculpture. Eventually, Selene was able to free herself, but at the cost of her power. Unable to return to Novia, Selene wandered aimlessly..', 'Experimental Robe', 'Experimental Ice Bracelet', 'SPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Selva', 'Selva [Character]', 'Selva', 'recruit', '["leather"]', '["sword","armshield","rap"]', -130, -650, 'portrait', 70, 70, 50, 50, 50, 50, 60, 'A settler from Bristia who lost her left hand and lover to Viscount Montoro. Will her obsession with legacy of Feruccio be requited with the death of Montoro and the restoration of her hand?', 'Crecemento Leather', 'Crecemento Rapier', 'Block', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Dobaselrane', 'Senior Magic Corps Dolores [Character]', 'Senior Magic Corps Dolores', 'cash', '["coat","robe"]', '["lightbrac"]', -1885, -130, 'portrait', 40, 50, 60, 40, 90, 70, 100, 'After studying in the Vespanola Prestigious Private School, Dolores returned to Illier and applied for the Magic Corps. With the help of her natural-born talent, she was quickly able to cast magic in various fields which made her join the Magic Corps with top grades. Her twin sister, Loraine, also joined the Magic Corps in second place in the same year and once again the family of Baselrane was revered as prestigious by the people of Illier.', 'Experimental Coat', 'Experimental Light Brc', 'Cast Time', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Seolhwa', 'Seol Hwa [Character]', 'Seol Hwa', 'cash', '["leather","coat"]', '["dag"]', -1950, -650, 'portrait', 90, 70, 60, 30, 50, 50, 100, 'Coria&amp;apos;s best Taoist. Born into a family that practiced the Taoist Arts, Seol Hwa learned all of the Taoist Arts passed down to Coria at a young age and further honed them in her own way. Knowing that she possesses more power than others, Seol Hwa sets out to find Coria&amp;apos;s greatest fighter, the White Dragon, to fulfill her childhood dream...', 'Experimental Leather', 'Experimental Dagger', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Barrelrare', 'Sergeant Barrol [Character]', 'Sergeant Barrol', 'cash', '["coat"]', '["pistol"]', -1560, -390, 'portrait', 40, 60, 60, 90, 50, 40, 100, 'Sergeant of the Bristia armed forces. It may look like all he does is wander around drunk, but Barrol continues to perform all of his duties in the army. He now seems ready to turn a new leaf ahead of the war between Bristia and Vespanola.', 'Experimental Coat', 'Experimental Pistol', 'Critical Damage', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sharon2', 'Sharon the Sage [Character]', 'Sharon the Sage', 'cash', '["coat"]', '["staff"]', -1690, -325, 'portrait', 35, 40, 40, 50, 95, 80, 100, 'After Count Cortes&amp;apos; death, Sharon asked for the compensations for her service. However, the count&amp;apos;s heir rejected Sharon&amp;apos;s request, who was no longer worthy and rather sent the soldiers to threaten and drive her away. Denied her loyalty, she decides to avenge the count and roams all over the continent looking for helpers to support her...', 'Experimental Coat', 'Experimental Staff', 'ATK to Monsters', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sherry', 'Sherry [Character]', 'Sherry', 'cash', '["leather"]', '["knuckle"]', -1755, -195, 'portrait', 70, 80, 50, 40, 40, 60, 100, 'A dancer who was once one of the many hands of Arsene. After the fall of Arsene Circus, she joined Noche Estelada, led by Conductor Rio, hiding her identity and collecting information.', 'Experimental Leather', 'Experimental Knuckle', 'ATK to PC', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SierraLosPC', 'Sierra Rose [Character]', 'Sierra Rose', 'recruit', '["robe"]', '["rod","elebrac"]', -780, -65, 'portrait', 40, 50, 40, 50, 90, 70, 100, 'The last key for the 5 Elementals bequeathed by Ferruccio Espada. She is a little witch who are embracing Corazon. She still cannot control her power on her own will.', 'Crecemento Robe', 'Crecemento Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ziz2', 'Silaen [Character]', 'Silaen', 'cash', '["coat"]', '["lightbrac"]', 0, -585, 'portrait02', 40, 40, 60, 40, 90, 70, 100, 'One of the three great demons that had reigned as apex predators since before the Master of the Five Elements descended upon the world. Now she has taken on the form of a mortal, the very being she hates most, and the rift has split her from one whole self to two. She keeps her identity hidden under a pseudonym in order to regain her original form and power.', 'Experimental Coat', 'Experimental Light Brc', 'Accuracy', 2, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('LynnRare', 'Silver Flash Lynn [Character]', 'Silver Flash Lynn', 'cash', '["leather","metal"]', '["gs"]', -1040, -325, 'portrait', 80, 70, 70, 40, 40, 50, 100, 'The knight family, Herberthe has protected Iiller imperial for generations, and she was a second daughter. Everybody expected that she would be the imperial guard, but she bow took a vow to the little princess of the Vernier. She followed her master when the little princess entered Vespanola, and since she overwhelmed the Vespanola knights who looked down on the little princess, she made a big name.', 'Experimental Metal', 'Experimental Great Sword', 'DEF', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('hknight', 'Sirius [Character]', 'Sirius', 'recruit', '["leather","metal"]', '["sword","shield","blunt"]', -780, -715, 'portrait', 60, 60, 80, 50, 40, 50, 100, 'A crusader of Armonia. He lost his parents at an early age and was raised in the monastery of Armonia. He rose through the rank of deputy leader of the crusaders through his firm conviction and talent in battle. He believes his sacred duty from God is to purify the herd of Abyss.', 'Crecemento Leather', 'Crecemento Sword', 'HP', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('GraceSniper', 'Sniper Bernelli [Character]', 'Sniper Bernelli', 'accomplish', '["coat"]', '["pistol","rifle"]', -650, -520, 'portrait', 40, 70, 40, 90, 30, 50, 100, 'Young Bernelli, when she did activities as sniper. Says she had an excellent skill of shooting but had trouble with hiding by her white hair.', 'Experimental Coat', 'Experimental Bayonet', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('BertheIce', 'Snowflake Berthe and Charles [Character]', 'Snowflake Berthe and Charles', 'cash', '["coat","robe"]', '["staff","magscroll"]', -1300, -65, 'portrait', 50, 60, 40, 50, 90, 60, 100, '&amp;apos;Berthe and Charles, who were dressed up like a king and queen of the ice kingdom.Charles made Berthe wear the dress obstinately, Berthe seems not to hate with that.&amp;apos;', 'Experimental Coat', 'Experimental Book', 'ATK to Monsters', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SherlinICE', 'Snowflake Cherlyn [Character]', 'Snowflake Cherlyn', 'cash', '["robe"]', '["icebrac","magscroll"]', -780, -455, 'portrait', 40, 40, 45, 55, 80, 60, 100, 'She was under Hernandez&amp;apos; command and in charge of collecting unique phenomenon and items going through Granado Espada. She didn&amp;apos;t think to have a feud with Family, so she joined with them.', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('IceMontoro', 'Snowflake Montoro [Character]', 'Snowflake Montoro', 'cash', '["coat"]', '["rod","staff"]', -975, -390, 'portrait', 40, 40, 50, 50, 90, 70, 100, 'To celabrate Christmas, dressing himself, Montoro. He feels the mood of the festival only, seems that don&amp;apos;t know the meaning of Christmas.', 'Experimental Coat', 'Experimental Rod', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Soho', 'Soho [Character]', 'Soho', 'recruit', '["leather"]', '["dag","rosario"]', -65, -325, 'portrait', 60, 70, 50, 60, 30, 50, 20, 'Soho, a part of the second generation of Coimbrans. He has a large store of SP and is also adept at physical attacks. He can use Fortitudo and Escrima.', 'Crecemento Leather', 'Crecemento Dagger', 'Critical Damage', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SohoFighter', 'Soho The Wind [Character]', 'Soho The Wind', 'cash', '["leather"]', '["knuckle","dag","rosario"]', -325, -455, 'portrait', 70, 70, 60, 60, 30, 50, 40, 'Soho, a part of the second generation of Coimbrans. He has a large store of SP and is also adept at physical attacks. He can use Fortitudo and Escrima.', 'Experimental Leather', 'Experimental Dagger', 'Evasion', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Soldier', 'Soldier of Reboldoeux [Character]', 'Soldier of Reboldoeux', 'recruit', '["leather","metal"]', '["pole","sword","shield","blunt"]', 0, -195, 'portrait', 60, 50, 70, 40, 30, 50, 1, 'A soldier responsible for the security in the City of Reboldoeux. He uses Sword and Polearm stances like those of Fighters.', 'Crecemento Leather', 'Crecemento Sword, Crecemento Shield', 'HP', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sorang', 'Sorang [Character]', 'Sorang', 'accomplish', '["leather"]', '["knuckle"]', -650, -325, 'portrait', 60, 85, 50, 50, 30, 60, 100, 'A sister of Soso. She came to Granado Espada to look for her sister who has not been in contact for a long time. She is stifled by seeing her sister traveling around and forgetting her purpose.', 'Experimental Leather', 'Experimental Knuckle', 'Evasion', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sorscha', 'Sorscha [Character]', 'Sorscha', 'cash', '["leather"]', '[]', -1820, -65, 'portrait', 70, 70, 70, 50, 50, 50, 100, 'A member of the Hutton family, famous for swordsmanship. At a young age, she blossomed extraordinary talents that were rarely seen in the family&amp;apos;s history and volunteered for the position of Fencer Master. Although not all existing Fencer masters in history were from the Hutton family, it is said that no one could replace a volunteering Hutton with their skills. Her request was fully supported both inside and outside the family for the same reason.', 'Experimental Leather', 'Experimental Rapier', 'Immunity', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Soso', 'Soso [Character]', 'Soso', 'recruit', '["leather"]', '["knuckle"]', -325, -520, 'portrait', 65, 80, 50, 50, 30, 50, 40, 'The daughter of the Chief of the Royal Guards is a trained professional in the martial arts of Dang and uses different stances.', 'Crecemento Leather', 'Crecemento Knuckle', 'AGI', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SpyOlivia', 'Spy Olivia [Character]', 'Spy Olivia', 'accomplish', '["leather"]', '["dag"]', -715, -260, 'portrait', 70, 80, 60, 50, 30, 50, 100, 'The figure of Olivia when she was doing spy works. Her combat skills and skills are bit different from Olivia&amp;apos;s.', 'Experimental Leather', 'Experimental Dagger', 'ASPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('SLudin', 'Student President Ludin [Character]', 'Student President Ludin', 'cash', '["robe"]', '["firebrac"]', -910, -65, 'portrait', 40, 40, 50, 50, 95, 70, 100, '16-year-old Ludin is the student president of the prestigious private school in Vespanola. She dosen&amp;apos;t work at all but seems to have no problem, owing to the capable vice president.', 'Experimental Robe', 'Experimental Fire  Bracelet', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Kano2Rare', 'Supreme Commander Kano [Character]', 'Supreme Commander Kano', 'cash', '["robe"]', '["magscroll"]', -1235, -65, 'portrait', 40, 50, 55, 40, 90, 70, 100, 'The current Supreme Commander in Bristia Army. Since the conversation with the governor, she could understand him and received full supports from Bristians. Finally she was appointed  as the supreme commander of Bristia. She is kind of timid, but if she makes a decision according to her faith, it said that she wouldn&amp;apos;t change his opinion for anything.', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Sylvestia', 'Sylvestia  [Character]', 'Sylvestia', 'cash', '["leather","robe"]', '["rap"]', -65, -65, 'portrait02', 80, 75, 60, 45, 30, 60, 100, 'A noble lady destined to lead the Medici family in place of her brother. Sylvestia, a luxury collector with a passion for Andre&amp;apos;s works, once revered him as a mentor. However, his departure to the New Continent gradually dimmed her admiration. As she prepared to inherit the family, her doubts about the Illier Warlords&amp;apos; conflicts grew. Troubling rumors from the continent finally drove her to embark on a journey to the New Continent.', 'Experimental Leather', 'Experimental Rapier', 'Immunity', 1, 1);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Tiburon', 'Tiburon [Character]', 'Tiburon', 'recruit', '["leather"]', '["sword","dag"]', -325, -65, 'portrait', 60, 80, 40, 50, 40, 50, 20, 'Second generation of the new continent settlers. An immature and cheeky boy, with a selfish personality. Weak against the strong and strong against the weak. His overall stats are low due to his small size, but has very high agility. He holds a dagger in his one-handed sword stance and a normal sword in his greatsword stance.', 'Crecemento Leather', 'Crecemento Sword', 'ATK', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Tom', 'Tom [Character]', 'Tom', 'cash', '["leather"]', '["dag"]', -1625, -715, 'portrait', 80, 60, 70, 40, 40, 50, 100, 'A surgeon of Burlon who saved a professional killer in the past and medically takes care of the people abandoned in the present. He used to work in the old-continent but heads his way to the new continent after a call from Moon. Sometimes, he seems to recollect someone along with the past.', 'Experimental Leather', 'Experimental Dagger', 'Damage from PC', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Tora', 'Tora [Character]', 'Tora', 'recruit', '["leather"]', '["dag","jav"]', -585, -585, 'portrait', 80, 80, 70, 40, 30, 50, 100, 'The son of Bardi and legendary Burlon, the grandson of Oswalt. He is always dreaming to revenge on Adelina since his father has been killed by her when he was young.', 'Crecemento Leather', 'Crecemento Dagger', 'HP Absorbation', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Valleria', 'Valeria [Character]', 'Valeria', 'recruit', '["robe"]', '["rosario"]', -455, -455, 'portrait', 30, 50, 40, 50, 80, 50, 60, 'The twin younger sister of Princess Gabriella, who was held in a state of suspended animation at the deepest part of Jaquin. After her rescue, she is learning about the world but still has a long way to go. She can use the Ancient Restoring Stance, which has been awakened by her pure soul.', 'Crecemento Robe', 'No Weapon', 'HP Recovery', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Vendetta', 'Valeria Vendetta [Character]', 'Valeria Vendetta', 'recruit', '["coat"]', '["rap"]', -715, 0, 'portrait', 65, 75, 60, 50, 40, 50, 100, 'A figure of Valeria who has vanished her innocent by knowing her origin and conspiracies. The only remained things for her are hatred and voidness to her father.', 'Experimental Coat', 'Experimental Rapier', 'SPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Van', 'Van [Character]', 'Van', 'recruit', '["coat","robe"]', '["magscroll"]', -975, -325, 'portrait', 40, 50, 70, 50, 90, 40, 100, 'He belongs to the &amp;apos;Memento Mori&amp;apos; that is known as Dark Ground worked in the history of past. Currently, he is trying to achieve the ideal of &amp;apos;Memento Mori&amp;apos; to actualize their dream world.', 'Crecemento Robe', 'No Weapon', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Vanessa', 'Vanessa [Character]', 'Vanessa', 'cash', '["leather"]', '["sabre"]', -1170, -390, 'portrait', 80, 80, 70, 40, 30, 50, 100, 'One of Pegadilla mercenaries. A female mercenary who got the best battle skills. She regards Calyce as a rival.', 'Experimental Leather', 'Experimental Sabre', 'ASPD', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Veatrice', 'Veatrice [Character]', 'Veatrice', 'recruit', '["coat","robe"]', '["lightbrac"]', -585, 0, 'portrait', 40, 40, 55, 50, 85, 60, 60, 'She is Absinian, the real sister of M&amp;apos;Boma and she was an excellent woman warrior since she was young. Recently, she left her hometown and met her brother while wandering around the world and came to the new continent together.', 'Crecemento Robe', 'Crecemento Lightning Bracelet', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Veil', 'Veil [Character]', 'Veil', 'recruit', '["coat"]', '["xbow"]', -715, -390, 'portrait', 50, 50, 60, 90, 30, 50, 100, 'He is the one who has constructed Resistance leading the remnants to the woods after the Bristia&amp;apos;s defeat in the Three-Year War. He is impetuous and likes to receive attentions. According to rumors, he was promoted to captain rapidly by his achievement that he did to look cool during the Three-Year War.', 'Crecemento Coat', 'Crecemento Crossbow', 'SPD', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Berroniff', 'Veronif [Character]', 'Veronif', 'recruit', '["coat","robe"]', '["rosario","magscroll"]', -520, -325, 'portrait', 40, 30, 40, 50, 90, 70, 60, 'An alchemist from Illier. She despises every new continent pioneers from the inner depths of her heart, ever since her ex-lover abandoned her and left for the new continent.', 'Crecemento Robe', 'No Weapon', 'INT', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Viki', 'Viki [Character]', 'Viki', 'recruit', '["leather"]', '["pendant","rosario"]', -260, -520, 'portrait', 40, 50, 40, 50, 50, 70, 20, 'An adorable boy who lives with his grandfather and uses scout and summon skills.', 'Crecemento Leather', 'No Weapon', 'SEN', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Vincent', 'Vincent [Character]', 'Vincent', 'recruit', '["coat","robe"]', '["rosario","staff","magscroll"]', -585, -65, 'portrait', 50, 50, 60, 50, 70, 40, 60, 'He belongs to the &amp;apos;Memento Mori&amp;apos; that is known as Dark Ground worked in the history of past. Currently, he is trying to achieve the ideal of &amp;apos;Memento Mori&amp;apos; to actualize their dream world.', 'Crecemento Coat', 'No Weapon', 'HP Absorbation', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Violet', 'Violet [Character]', 'Violet', 'cash', '["leather","metal"]', '["blunt"]', -1690, -195, 'portrait', 80, 40, 80, 50, 40, 50, 100, 'Successor of the family renowned throughout the continent, the Valerons. She was adopted by Arpe Valeron, who recognized her talent during her time at the orphanage. They say that she inherits Valeron&amp;apos;s esoterica but she actually does not seem to be much interested in it...', 'Experimental Metal', 'Experimental Hammer', 'STR', 2, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('KaelRare', 'White Wolf [Character]', 'White Wolf', 'cash', '["leather"]', '["sabre"]', -1365, -130, 'portrait', 75, 70, 65, 40, 40, 50, 100, 'Mysterious dire wolf Wolf which makes Illier loud. He is proving his Kan del Jena by shaking the noble houses today.', 'Experimental Leather', 'Experimental Sabre', 'ATK', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('WinonaEnde', 'Winona [Character]', 'Winona', 'cash', '["robe"]', '["rod","shield","staff"]', -1950, -130, 'portrait', 50, 30, 40, 50, 60, 50, 100, 'Linker Master Winona Ende is a rarity in the history of wizardry, which has seen its fair share of geniuses. She turned an apple into a ball at age 11, and the next year she was talented enough to transfer rust on a weapon into the body of a threatening opponent. Linking monsters of the same species to deal damage at the same time is less than eating a piece of cake to her.', 'Experimental Robe', 'Experimental Rod', 'ALL RES', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Yeganeh', 'Yeganeh [Character]', 'Yeganeh', 'recruit', '["leather"]', '["sword","hammer"]', -260, -195, 'portrait', 60, 50, 50, 70, 40, 50, 40, 'Yeganeh the Carpenter in Cite de Reboldoeux. He once lived a life tainted by blood, but has turned over a new leaf and often helps those in need. He uses the Construction stance to assist other members, and possesses a strong Attack.', 'Crecemento Leather', 'Crecemento Sword', 'DEX', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Zaved', 'Zaved [Character]', 'Zaved', 'cash', '["robe"]', '["magscroll"]', -1560, -65, 'portrait', 35, 50, 55, 50, 85, 65, 100, 'Zaved, alchemist Karin&amp;apos;s assistant. She came to Granado Espada by Teresia&amp;apos;s request, and now she is on a journey to investigate Porto Bello together with [Leng].', 'Experimental Robe', 'Experimental Book', 'INT', 1, 0);
INSERT OR REPLACE INTO characters (slug, name, display_name, type, armor_types, weapons, portrait_x, portrait_y, portrait_class, str, agi, hp, dex, int_stat, sen, starting_level, bio, starting_armor, starting_weapon, buff, buff_level, is_new) VALUES ('Ziz', 'Ziz [Character]', 'Ziz', 'cash', '["coat"]', '["lightbrac"]', 0, -520, 'portrait02', 40, 40, 60, 40, 90, 70, 100, 'One of the three great demons that had reigned as apex predators since before the Master of the Five Elements descended upon the world. Now she has taken on the form of a mortal, the very being she hates most, and the rift has split her from one whole self to two. She hides the identity of her other self, gathering information and biding her time in order to regain her original form and power.', 'Experimental Coat', 'Experimental Light Brc', 'Accuracy', 2, 0);

